const koreanCuisineData = [
  // ── APPETIZERS ─────────────────────────────────────────────────────────────
  { dish_name:"Pajeon (Korean Scallion Pancakes)", state:"Korea", cuisine:"Korean", category:"Appetizers", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:15, total_time_minutes:30, servings:4, short_description:"Crispy, golden Korean savoury pancakes packed with spring onion and seafood, served with a tangy soy dipping sauce. A beloved Korean street food and drinking snack.", ingredients:[{name:"Spring onion",quantity:"200",unit:"g"},{name:"Flour",quantity:"150",unit:"g"},{name:"Rice flour",quantity:"50",unit:"g"},{name:"Egg",quantity:"1",unit:"large"},{name:"Cold water",quantity:"200",unit:"ml"},{name:"Squid or prawns",quantity:"150",unit:"g"},{name:"Soy sauce",quantity:"3",unit:"tbsp"},{name:"Rice vinegar",quantity:"2",unit:"tbsp"},{name:"Sesame oil",quantity:"1",unit:"tsp"},{name:"Oil for frying",quantity:"4",unit:"tbsp"}], preparation_steps:["Mix flour, rice flour, egg and cold water into smooth batter.","Cut spring onions into long pieces. Slice seafood thinly.","Heat oil in pan until very hot.","Pour batter in thin layer. Arrange spring onions and seafood on top.","Press down firmly. Cook 4-5 minutes until golden and crispy.","Flip carefully. Cook other side 3-4 minutes.","Make dipping sauce: mix soy sauce, vinegar, sesame oil and chilli flakes.","Cut into pieces and serve immediately."], chef_notes:"Cold water and rice flour are the secrets to an extra crispy pajeon. The batter should be thin — thick batter makes a doughy pancake. Maximum heat is essential.", serving_suggestions:"Serve cut into pieces with soy dipping sauce. Perfect with makgeolli rice wine.", nutrition_estimate:{calories:"285",protein_g:"14",carbohydrates_g:"36",fat_g:"9"}, tags:["Pancake","Street Food","Crispy","Korean"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Tteokbokki (Spicy Rice Cakes)", state:"Korea", cuisine:"Korean", category:"Appetizers", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:15, total_time_minutes:25, servings:4, short_description:"Korea's most iconic street food — chewy cylindrical rice cakes simmered in a fiery, sweet gochujang sauce with fish cakes and boiled eggs. Addictively delicious.", ingredients:[{name:"Tteok (rice cake cylinders)",quantity:"400",unit:"g"},{name:"Fish cake (eomuk)",quantity:"200",unit:"g"},{name:"Gochujang (red chilli paste)",quantity:"4",unit:"tbsp"},{name:"Gochugaru (chilli flakes)",quantity:"2",unit:"tsp"},{name:"Soy sauce",quantity:"2",unit:"tbsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Anchovy stock",quantity:"500",unit:"ml"},{name:"Spring onion",quantity:"3",unit:"stalks"},{name:"Boiled eggs",quantity:"2",unit:"pieces"}], preparation_steps:["Make anchovy stock: simmer dried anchovies and kelp 10 minutes. Strain.","Mix gochujang, gochugaru, soy sauce, sugar and garlic into sauce.","Bring stock to boil. Add sauce and stir.","Add rice cakes and fish cakes.","Simmer 10 minutes until sauce thickens and rice cakes are soft.","Add halved boiled eggs.","Garnish with spring onion and sesame seeds.","Serve hot immediately."], chef_notes:"The anchovy-kelp stock is the foundation — it adds a deep umami that water cannot replicate. Rice cakes should be soft but still chewy — not mushy.", serving_suggestions:"Serve piping hot as a street snack. Provide extra gochujang on the side.", nutrition_estimate:{calories:"345",protein_g:"12",carbohydrates_g:"62",fat_g:"6"}, tags:["Street Food","Spicy","Rice Cakes","Iconic Korean"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Japchae (Glass Noodle Stir-Fry)", state:"Korea", cuisine:"Korean", category:"Appetizers", difficulty_level:"Medium", prep_time_minutes:30, cook_time_minutes:20, total_time_minutes:50, servings:4, short_description:"Korea's beloved glass noodle dish — sweet potato starch noodles stir-fried with colourful vegetables, beef and a sweet soy sauce. Served at every Korean celebration.", ingredients:[{name:"Dangmyeon (glass noodles)",quantity:"200",unit:"g"},{name:"Beef sirloin",quantity:"150",unit:"g"},{name:"Spinach",quantity:"150",unit:"g"},{name:"Carrot",quantity:"1",unit:"large"},{name:"Onion",quantity:"1",unit:"large"},{name:"Shiitake mushrooms",quantity:"6",unit:"pieces"},{name:"Soy sauce",quantity:"4",unit:"tbsp"},{name:"Sesame oil",quantity:"2",unit:"tbsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"}], preparation_steps:["Soak noodles in hot water 20 minutes. Boil 5 minutes until cooked. Drain and toss with sesame oil.","Blanch spinach 30 seconds. Squeeze dry and season with soy and sesame oil.","Julienne carrot and onion. Slice mushrooms.","Stir-fry each vegetable separately with garlic and soy sauce.","Marinate beef in soy, sugar, garlic and sesame oil. Stir-fry until cooked.","Combine all ingredients: noodles, beef and all vegetables.","Season with soy sauce, sesame oil and sugar.","Toss well and top with sesame seeds."], chef_notes:"Each ingredient is cooked separately to maintain individual colours and textures — this is the traditional method. The noodles should be glossy and silky, not clumped.", serving_suggestions:"Serve at room temperature as a side dish or starter. Essential at Korean celebrations.", nutrition_estimate:{calories:"345",protein_g:"14",carbohydrates_g:"52",fat_g:"10"}, tags:["Glass Noodles","Celebration","Korean Classic","Colourful"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Mandu (Korean Dumplings)", state:"Korea", cuisine:"Korean", category:"Appetizers", difficulty_level:"Medium", prep_time_minutes:45, cook_time_minutes:15, total_time_minutes:60, servings:4, short_description:"Plump Korean dumplings filled with pork, tofu, kimchi and glass noodles — steamed, pan-fried or boiled. A beloved Korean comfort food eaten year-round.", ingredients:[{name:"Dumpling wrappers",quantity:"30",unit:"pieces"},{name:"Ground pork",quantity:"200",unit:"g"},{name:"Firm tofu",quantity:"150",unit:"g"},{name:"Kimchi",quantity:"100",unit:"g"},{name:"Glass noodles",quantity:"50",unit:"g"},{name:"Garlic",quantity:"3",unit:"cloves"},{name:"Ginger",quantity:"0.5",unit:"inch"},{name:"Soy sauce",quantity:"2",unit:"tbsp"},{name:"Sesame oil",quantity:"1",unit:"tbsp"},{name:"Spring onion",quantity:"3",unit:"stalks"}], preparation_steps:["Soak noodles and cut into short pieces.","Press tofu dry and crumble. Squeeze excess liquid from kimchi and chop.","Mix pork, tofu, kimchi, noodles, garlic, ginger, soy and sesame oil.","Place filling in wrapper centre. Fold and pleat edges to seal.","For pan-fried: cook in oiled pan until golden. Add water and steam covered.","For steamed: steam 12 minutes over high heat.","For boiled: cook in soup until they float.","Serve with soy-vinegar dipping sauce."], chef_notes:"Pressing all moisture from tofu and kimchi is essential — excess liquid makes soggy mandu. The filling should be sticky enough to hold its shape.", serving_suggestions:"Serve with soy-vinegar dipping sauce. Add to tteok mandu guk soup for a New Year tradition.", nutrition_estimate:{calories:"265",protein_g:"14",carbohydrates_g:"32",fat_g:"9"}, tags:["Dumplings","Comfort Food","Kimchi","Korean"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Bindaetteok (Mung Bean Pancakes)", state:"Korea", cuisine:"Korean", category:"Appetizers", difficulty_level:"Medium", prep_time_minutes:60, cook_time_minutes:20, total_time_minutes:80, servings:4, short_description:"Ancient Korean mung bean pancakes — ground soaked mung beans mixed with kimchi and pork, pan-fried until wonderfully crispy. A traditional market food.", ingredients:[{name:"Dried mung beans",quantity:"200",unit:"g"},{name:"Pork belly",quantity:"100",unit:"g"},{name:"Kimchi",quantity:"100",unit:"g"},{name:"Bean sprouts",quantity:"100",unit:"g"},{name:"Spring onion",quantity:"4",unit:"stalks"},{name:"Garlic",quantity:"3",unit:"cloves"},{name:"Salt",quantity:"1",unit:"tsp"},{name:"Sesame oil",quantity:"1",unit:"tbsp"},{name:"Oil for frying",quantity:"4",unit:"tbsp"}], preparation_steps:["Soak mung beans overnight. Drain and grind coarsely — keep some texture.","Squeeze excess liquid from kimchi and chop.","Mix ground beans, kimchi, pork, bean sprouts, spring onion and garlic.","Season with salt and sesame oil.","Heat oil in pan over medium-high heat.","Drop spoonfuls and flatten into round pancakes.","Fry 4 minutes per side until crispy and golden.","Serve with soy dipping sauce."], chef_notes:"The batter should be thick enough to hold shape but not too stiff. Coarsely grinding the beans preserves texture — a smooth paste makes dense pancakes.", serving_suggestions:"Serve hot from the pan at traditional Korean markets style.", nutrition_estimate:{calories:"285",protein_g:"14",carbohydrates_g:"32",fat_g:"12"}, tags:["Mung Bean","Traditional","Market Food","Korean"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Gamja Jorim (Braised Potatoes)", state:"Korea", cuisine:"Korean", category:"Appetizers", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:20, total_time_minutes:30, servings:4, short_description:"Small potatoes braised in a sweet and spicy soy glaze until sticky and caramelised — one of Korea's most popular banchan (side dishes).", ingredients:[{name:"Baby potatoes",quantity:"500",unit:"g"},{name:"Soy sauce",quantity:"3",unit:"tbsp"},{name:"Gochujang",quantity:"1",unit:"tbsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Sesame oil",quantity:"1",unit:"tbsp"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"},{name:"Water",quantity:"100",unit:"ml"},{name:"Oil",quantity:"2",unit:"tbsp"}], preparation_steps:["Halve baby potatoes if large. Fry in oil until golden outside.","Mix soy sauce, gochujang, sugar, garlic and water into sauce.","Pour sauce over potatoes.","Cook over medium heat stirring regularly until sauce reduces and coats potatoes.","Continue until sauce becomes thick and sticky.","Drizzle sesame oil and toss with sesame seeds.","Serve at room temperature as banchan."], chef_notes:"The potatoes must be fried first to create a slightly crispy exterior that absorbs the glaze beautifully. Keep stirring in the final stages to prevent burning.", serving_suggestions:"Serve as banchan alongside rice and other Korean dishes.", nutrition_estimate:{calories:"205",protein_g:"3",carbohydrates_g:"38",fat_g:"6"}, tags:["Banchan","Potatoes","Sweet-Spicy","Korean"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Gyeran Jjim (Steamed Egg Custard)", state:"Korea", cuisine:"Korean", category:"Appetizers", difficulty_level:"Easy", prep_time_minutes:5, cook_time_minutes:15, total_time_minutes:20, servings:4, short_description:"A fluffy, soufflé-like steamed egg custard cooked in a stone pot — silky smooth inside with a beautifully puffed top. Korea's most comforting side dish.", ingredients:[{name:"Eggs",quantity:"4",unit:"large"},{name:"Anchovy stock",quantity:"200",unit:"ml"},{name:"Spring onion",quantity:"2",unit:"stalks"},{name:"Soy sauce",quantity:"1",unit:"tbsp"},{name:"Salt",quantity:"0.5",unit:"tsp"},{name:"Sesame oil",quantity:"1",unit:"tsp"},{name:"Sesame seeds",quantity:"1",unit:"tbsp"}], preparation_steps:["Beat eggs well until completely combined.","Mix in anchovy stock, soy sauce and salt.","Strain through fine sieve for smooth texture.","Pour into stone pot or oven-safe dish.","Steam over medium heat for 12-15 minutes.","Alternatively, microwave 3-4 minutes checking frequently.","Top should puff up dramatically.","Garnish with spring onion, sesame oil and seeds."], chef_notes:"The stone pot (dolsot) conducts heat evenly creating the characteristic puffed top. The egg ratio to liquid determines softness — more stock makes it silkier.", serving_suggestions:"Serve immediately in the stone pot as a banchan. It deflates quickly.", nutrition_estimate:{calories:"105",protein_g:"9",carbohydrates_g:"2",fat_g:"7"}, tags:["Egg","Steamed","Banchan","Comforting"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Hobak Jeon (Zucchini Pancakes)", state:"Korea", cuisine:"Korean", category:"Appetizers", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:15, total_time_minutes:30, servings:4, short_description:"Thin, delicate Korean zucchini pancakes — slices of zucchini dipped in egg and pan-fried until golden. A simple, elegant banchan found at every Korean table.", ingredients:[{name:"Zucchini",quantity:"2",unit:"large"},{name:"Eggs",quantity:"3",unit:"large"},{name:"Flour",quantity:"80",unit:"g"},{name:"Salt",quantity:"1",unit:"tsp"},{name:"Oil",quantity:"3",unit:"tbsp"},{name:"Soy sauce",quantity:"2",unit:"tbsp"},{name:"Rice vinegar",quantity:"1",unit:"tbsp"},{name:"Sesame oil",quantity:"1",unit:"tsp"}], preparation_steps:["Slice zucchini into 5mm rounds.","Salt zucchini slices and rest 10 minutes. Pat dry.","Dust in flour shaking off excess.","Dip in beaten egg.","Pan-fry in oil over medium heat 2-3 minutes per side until golden.","Make dipping sauce: soy sauce, vinegar and sesame oil.","Arrange on plate.","Serve with dipping sauce."], chef_notes:"Salting and drying the zucchini removes excess moisture that would make the batter soggy. The egg coating should be thin and even.", serving_suggestions:"Serve as banchan alongside other Korean dishes and rice.", nutrition_estimate:{calories:"145",protein_g:"6",carbohydrates_g:"14",fat_g:"8"}, tags:["Zucchini","Banchan","Simple","Korean"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Dubu Jorim (Spicy Braised Tofu)", state:"Korea", cuisine:"Korean", category:"Appetizers", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:15, total_time_minutes:25, servings:4, short_description:"Crispy pan-fried tofu braised in a spicy, savory sauce of gochugaru, soy and garlic — one of Korea's most popular and satisfying vegetarian banchan.", ingredients:[{name:"Firm tofu",quantity:"400",unit:"g"},{name:"Gochugaru (chilli flakes)",quantity:"2",unit:"tbsp"},{name:"Soy sauce",quantity:"3",unit:"tbsp"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Sugar",quantity:"1",unit:"tbsp"},{name:"Sesame oil",quantity:"1",unit:"tbsp"},{name:"Spring onion",quantity:"3",unit:"stalks"},{name:"Oil",quantity:"3",unit:"tbsp"},{name:"Water",quantity:"4",unit:"tbsp"}], preparation_steps:["Cut tofu into rectangles. Pat completely dry with paper towels.","Pan-fry tofu in oil until golden and crispy on both sides.","Mix gochugaru, soy sauce, garlic, sugar and water into sauce.","Pour sauce over tofu in pan.","Cook over medium heat turning gently until sauce is absorbed.","Drizzle sesame oil.","Garnish with spring onion and sesame seeds.","Serve warm or at room temperature."], chef_notes:"Completely drying the tofu before frying is essential for crispiness. The tofu should be crispy enough to hold up when the sauce is added.", serving_suggestions:"Serve as a protein-rich banchan. Excellent over rice.", nutrition_estimate:{calories:"185",protein_g:"12",carbohydrates_g:"10",fat_g:"12"}, tags:["Tofu","Spicy","Vegetarian","Banchan"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Kimchi Pancake (Kimchijeon)", state:"Korea", cuisine:"Korean", category:"Appetizers", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:15, total_time_minutes:25, servings:4, short_description:"Crispy, tangy Korean kimchi pancakes — packed with well-fermented kimchi, green onions and sesame seeds. Sour, spicy and absolutely irresistible.", ingredients:[{name:"Ripe kimchi",quantity:"200",unit:"g"},{name:"Flour",quantity:"120",unit:"g"},{name:"Rice flour",quantity:"40",unit:"g"},{name:"Egg",quantity:"1",unit:"large"},{name:"Kimchi juice",quantity:"3",unit:"tbsp"},{name:"Spring onion",quantity:"4",unit:"stalks"},{name:"Cold water",quantity:"100",unit:"ml"},{name:"Sugar",quantity:"1",unit:"tsp"},{name:"Oil",quantity:"4",unit:"tbsp"}], preparation_steps:["Chop kimchi into small pieces. Reserve kimchi juice.","Mix flour, rice flour, egg, kimchi juice, cold water and sugar.","Fold in chopped kimchi and spring onion.","Heat generous oil in pan over medium-high heat.","Pour batter and spread into thin round pancake.","Cook 4-5 minutes until crispy and golden.","Flip and cook other side 3-4 minutes.","Cut and serve with soy dipping sauce."], chef_notes:"Well-fermented (sour) kimchi makes the best kimchijeon. The kimchi juice in the batter adds flavour and tang. Do not use fresh kimchi — it lacks the sourness.", serving_suggestions:"Serve cut into pieces with soy-vinegar dipping sauce.", nutrition_estimate:{calories:"245",protein_g:"7",carbohydrates_g:"36",fat_g:"9"}, tags:["Kimchi","Pancake","Crispy","Fermented"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },

  // ── SOUPS ───────────────────────────────────────────────────────────────────
  { dish_name:"Kimchi Jjigae (Kimchi Stew)", state:"Korea", cuisine:"Korean", category:"Soups", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:25, total_time_minutes:40, servings:4, short_description:"Korea's most beloved everyday stew — deeply flavoured with well-fermented kimchi, pork belly and tofu in a rich red broth. A national comfort food.", ingredients:[{name:"Ripe kimchi",quantity:"300",unit:"g"},{name:"Pork belly",quantity:"200",unit:"g"},{name:"Firm tofu",quantity:"200",unit:"g"},{name:"Gochugaru",quantity:"2",unit:"tbsp"},{name:"Gochujang",quantity:"1",unit:"tbsp"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Sesame oil",quantity:"1",unit:"tbsp"},{name:"Anchovy stock",quantity:"400",unit:"ml"},{name:"Spring onion",quantity:"3",unit:"stalks"},{name:"Soy sauce",quantity:"2",unit:"tbsp"}], preparation_steps:["Slice pork belly into bite-sized pieces. Fry in pot until fat renders.","Add kimchi and stir-fry with pork 3 minutes.","Add garlic, gochugaru and gochujang.","Pour in anchovy stock and kimchi juice if available.","Bring to boil then simmer 15 minutes.","Add tofu cubes gently.","Season with soy sauce.","Garnish with spring onion and sesame oil."], chef_notes:"Well-fermented kimchi is essential — fresh kimchi makes a bland stew. The more aged the kimchi, the deeper and more complex the flavour. Never use water instead of anchovy stock.", serving_suggestions:"Serve bubbling in a stone pot with steamed rice. Always eat with rice.", nutrition_estimate:{calories:"285",protein_g:"18",carbohydrates_g:"12",fat_g:"18"}, tags:["Kimchi","Stew","Comfort Food","Korean Essential"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Doenjang Jjigae (Soybean Paste Stew)", state:"Korea", cuisine:"Korean", category:"Soups", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:20, total_time_minutes:35, servings:4, short_description:"Korea's deeply nourishing soybean paste stew — earthy, umami-rich doenjang with tofu, zucchini and mushrooms. One of the most important dishes in Korean cuisine.", ingredients:[{name:"Doenjang (soybean paste)",quantity:"4",unit:"tbsp"},{name:"Firm tofu",quantity:"200",unit:"g"},{name:"Zucchini",quantity:"1",unit:"medium"},{name:"Mushrooms",quantity:"100",unit:"g"},{name:"Onion",quantity:"1",unit:"medium"},{name:"Anchovy-kelp stock",quantity:"600",unit:"ml"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Gochugaru",quantity:"1",unit:"tsp"},{name:"Spring onion",quantity:"3",unit:"stalks"}], preparation_steps:["Bring anchovy-kelp stock to boil.","Dissolve doenjang paste in a ladle of stock first.","Add dissolved doenjang to pot.","Add onion, zucchini and mushrooms.","Simmer 10 minutes.","Add tofu and garlic.","Cook 5 more minutes.","Garnish with spring onion and serve in stone pot."], chef_notes:"Doenjang has a powerful, complex flavour — more pungent than Japanese miso. Never boil aggressively after adding doenjang as it turns bitter. The anchovy-kelp stock is non-negotiable.", serving_suggestions:"Serve bubbling alongside rice and banchan. The stone pot keeps it hot throughout the meal.", nutrition_estimate:{calories:"145",protein_g:"10",carbohydrates_g:"12",fat_g:"6"}, tags:["Doenjang","Soybean","Nourishing","Korean Daily"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Galbitang (Short Rib Soup)", state:"Korea", cuisine:"Korean", category:"Soups", difficulty_level:"Medium", prep_time_minutes:20, cook_time_minutes:120, total_time_minutes:140, servings:4, short_description:"A deeply satisfying clear Korean soup of beef short ribs simmered for hours until the broth is silky and the meat falls off the bone — a luxury soup for special occasions.", ingredients:[{name:"Beef short ribs",quantity:"800",unit:"g"},{name:"Daikon radish",quantity:"300",unit:"g"},{name:"Garlic",quantity:"8",unit:"cloves"},{name:"Ginger",quantity:"1",unit:"inch"},{name:"Spring onion",quantity:"4",unit:"stalks"},{name:"Glass noodles",quantity:"100",unit:"g"},{name:"Soy sauce",quantity:"2",unit:"tbsp"},{name:"Salt",quantity:"1",unit:"tsp"},{name:"White pepper",quantity:"0.5",unit:"tsp"},{name:"Egg",quantity:"2",unit:"large"}], preparation_steps:["Soak ribs in cold water 1 hour to remove blood. Drain.","Blanch ribs in boiling water 5 minutes. Rinse.","Cover with fresh water, add daikon, garlic and ginger.","Simmer 1.5-2 hours until broth is rich and meat is tender.","Skim fat regularly.","Season with soy sauce, salt and white pepper.","Soak glass noodles and add to soup.","Make egg garnish: thin omelette cut into strips.","Serve with rice and kimchi."], chef_notes:"Soaking ribs in cold water removes blood which would cloud the broth. Constant skimming produces a beautifully clear soup. The radish absorbs and balances the beef richness.", serving_suggestions:"Serve in deep bowls garnished with egg strips and spring onion alongside rice.", nutrition_estimate:{calories:"385",protein_g:"32",carbohydrates_g:"18",fat_g:"22"}, tags:["Short Ribs","Clear Soup","Special Occasion","Korean"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Sundubu Jjigae (Soft Tofu Stew)", state:"Korea", cuisine:"Korean", category:"Soups", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:15, total_time_minutes:25, servings:4, short_description:"A fiery, bubbling stew of silken soft tofu with seafood, pork and a raw egg cracked in at the end — Korea's most famous restaurant stew, served in a screaming hot stone pot.", ingredients:[{name:"Silken soft tofu (sundubu)",quantity:"400",unit:"g"},{name:"Pork belly or seafood",quantity:"150",unit:"g"},{name:"Gochugaru",quantity:"3",unit:"tbsp"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Anchovy stock",quantity:"400",unit:"ml"},{name:"Sesame oil",quantity:"1",unit:"tbsp"},{name:"Eggs",quantity:"4",unit:"large"},{name:"Spring onion",quantity:"3",unit:"stalks"},{name:"Soy sauce",quantity:"1",unit:"tbsp"},{name:"Onion",quantity:"1",unit:"medium"}], preparation_steps:["Heat sesame oil in stone pot. Fry gochugaru 30 seconds.","Add garlic and onion. Fry 2 minutes.","Add pork or seafood. Fry until cooked.","Pour in anchovy stock. Bring to boil.","Add soft tofu in large spoonfuls — do not stir or it breaks.","Season with soy sauce.","Crack a raw egg into the centre of the bubbling stew.","Serve immediately while bubbling — the egg cooks at the table."], chef_notes:"The stone pot must be screaming hot when served — the egg continues cooking in the residual heat. Sundubu should be eaten as soon as it arrives — do not wait.", serving_suggestions:"Serve in individual stone pots with steamed rice on the side.", nutrition_estimate:{calories:"225",protein_g:"16",carbohydrates_g:"8",fat_g:"15"}, tags:["Soft Tofu","Spicy","Stone Pot","Korean Restaurant"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Seolleongtang (Ox Bone Soup)", state:"Korea", cuisine:"Korean", category:"Soups", difficulty_level:"Hard", prep_time_minutes:30, cook_time_minutes:480, total_time_minutes:510, servings:6, short_description:"Seoul's ancient ox bone soup — simmered for 8-12 hours until the broth turns creamy white and deeply nourishing. A Joseon Dynasty palace food that became a beloved Seoul staple.", ingredients:[{name:"Ox leg bones",quantity:"1.5",unit:"kg"},{name:"Brisket",quantity:"500",unit:"g"},{name:"Garlic",quantity:"10",unit:"cloves"},{name:"Ginger",quantity:"2",unit:"inch"},{name:"Salt",quantity:"2",unit:"tsp"},{name:"White pepper",quantity:"1",unit:"tsp"},{name:"Spring onion",quantity:"6",unit:"stalks"},{name:"Rice noodles or rice",quantity:"300",unit:"g"}], preparation_steps:["Soak bones in cold water 2 hours to remove blood.","Blanch bones in boiling water 10 minutes. Rinse thoroughly.","Cover bones with fresh water. Boil vigorously 30 minutes.","Add brisket, garlic and ginger. Reduce to strong simmer.","Simmer 6-8 hours adding water as needed.","The vigorous boil creates the milky white colour.","Remove brisket when tender. Slice thinly.","Season with salt only at the table."], chef_notes:"The milky white colour comes from boiling vigorously — the collagen emulsifies into the broth. Never add soy sauce to the broth — it is always seasoned with salt only at the table.", serving_suggestions:"Serve with sliced brisket, salt, pepper, spring onion and kimchi on the side.", nutrition_estimate:{calories:"265",protein_g:"28",carbohydrates_g:"8",fat_g:"14"}, tags:["Bone Broth","Seoul","8-Hour Cook","Nourishing"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Miyeok Guk (Seaweed Soup)", state:"Korea", cuisine:"Korean", category:"Soups", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:20, total_time_minutes:35, servings:4, short_description:"Korea's birthday soup — silky seaweed soup with beef in a light broth. Eaten on birthdays to honour mothers and served to new mothers for postpartum recovery.", ingredients:[{name:"Dried miyeok seaweed",quantity:"30",unit:"g"},{name:"Beef brisket",quantity:"150",unit:"g"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Soy sauce",quantity:"2",unit:"tbsp"},{name:"Sesame oil",quantity:"2",unit:"tbsp"},{name:"Salt",quantity:"0.5",unit:"tsp"},{name:"Water",quantity:"1.2",unit:"litres"}], preparation_steps:["Soak dried seaweed 20 minutes until expanded. Drain and cut.","Slice beef into thin strips.","Fry beef in sesame oil 2 minutes.","Add garlic and soy sauce. Fry 1 more minute.","Add seaweed and fry briefly.","Add water and bring to boil.","Simmer 15 minutes.","Season with salt.","Serve in bowls."], chef_notes:"Sesame oil is used for the initial frying — this is unique and gives miyeok guk its distinctive nutty richness. The seaweed expands dramatically when soaked.", serving_suggestions:"Eat on your birthday — it is considered bad luck not to. Serve with rice.", nutrition_estimate:{calories:"125",protein_g:"10",carbohydrates_g:"4",fat_g:"7"}, tags:["Birthday Soup","Seaweed","Korean Tradition","Postpartum"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Gamjatang (Pork Bone Soup)", state:"Korea", cuisine:"Korean", category:"Soups", difficulty_level:"Medium", prep_time_minutes:30, cook_time_minutes:90, total_time_minutes:120, servings:4, short_description:"A robust, deeply spiced Korean pork neck bone soup with perilla seeds, doenjang and vegetables — hearty, warming and deeply satisfying.", ingredients:[{name:"Pork neck bones",quantity:"1",unit:"kg"},{name:"Potatoes",quantity:"3",unit:"large"},{name:"Perilla seeds (deulgae)",quantity:"3",unit:"tbsp"},{name:"Doenjang",quantity:"2",unit:"tbsp"},{name:"Gochugaru",quantity:"3",unit:"tbsp"},{name:"Garlic",quantity:"8",unit:"cloves"},{name:"Ginger",quantity:"1",unit:"inch"},{name:"Spring onion",quantity:"4",unit:"stalks"},{name:"Perilla leaves",quantity:"10",unit:"leaves"},{name:"Sesame oil",quantity:"1",unit:"tbsp"}], preparation_steps:["Soak pork bones 1 hour. Blanch in boiling water 5 minutes. Rinse.","Cover with fresh water and simmer 1 hour.","Grind perilla seeds to coarse powder.","Make paste: gochugaru, doenjang, garlic, ginger and perilla seeds.","Add paste and potatoes to broth.","Simmer 30 minutes until potatoes are tender.","Season with salt.","Add perilla leaves and spring onion.","Drizzle sesame oil."], chef_notes:"Perilla seeds (deulgae) are the defining ingredient of gamjatang — their nutty, slightly bitter flavour is irreplaceable. Do not substitute with sesame seeds.", serving_suggestions:"Serve in a large stone pot at the table. Popular as a late-night hangover cure.", nutrition_estimate:{calories:"365",protein_g:"28",carbohydrates_g:"22",fat_g:"20"}, tags:["Pork Bone","Hearty","Perilla","Korean"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Samgyetang (Ginseng Chicken Soup)", state:"Korea", cuisine:"Korean", category:"Soups", difficulty_level:"Medium", prep_time_minutes:30, cook_time_minutes:90, total_time_minutes:120, servings:4, short_description:"Korea's ultimate tonic soup — a whole young chicken stuffed with glutinous rice, garlic, jujube and ginseng, simmered until the broth is silky and deeply nourishing.", ingredients:[{name:"Whole small chicken",quantity:"4",unit:"pieces"},{name:"Glutinous rice",quantity:"200",unit:"g"},{name:"Ginseng root",quantity:"4",unit:"pieces"},{name:"Jujube (dried dates)",quantity:"8",unit:"pieces"},{name:"Garlic",quantity:"16",unit:"cloves"},{name:"Ginger",quantity:"2",unit:"inch"},{name:"Salt",quantity:"1",unit:"tbsp"},{name:"White pepper",quantity:"1",unit:"tsp"},{name:"Spring onion",quantity:"4",unit:"stalks"}], preparation_steps:["Soak glutinous rice 30 minutes.","Stuff each chicken with rice, 2 garlic cloves, 1 jujube and ginseng.","Truss chicken legs to hold stuffing.","Place in individual pots with remaining garlic, jujube and ginger.","Cover with water. Bring to boil.","Simmer 1 hour until chicken is falling off the bone.","Season with salt and white pepper.","Serve each chicken in its own pot."], chef_notes:"Samgyetang is traditionally eaten on the hottest days of summer — Koreans believe fighting heat with heat expels toxins from the body. The whole chicken should be tender enough to pull apart with chopsticks.", serving_suggestions:"Serve one whole chicken per person in a clay pot with salt, pepper and kimchi.", nutrition_estimate:{calories:"425",protein_g:"42",carbohydrates_g:"28",fat_g:"16"}, tags:["Ginseng","Whole Chicken","Tonic","Summer"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Tteok Guk (Rice Cake Soup)", state:"Korea", cuisine:"Korean", category:"Soups", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:20, total_time_minutes:35, servings:4, short_description:"Korea's New Year soup — oval rice cakes in a clear beef broth, eaten on Seollal (Lunar New Year) to gain a year of age and good fortune.", ingredients:[{name:"Oval rice cakes (garaetteok)",quantity:"400",unit:"g"},{name:"Beef brisket",quantity:"200",unit:"g"},{name:"Eggs",quantity:"2",unit:"large"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Soy sauce",quantity:"2",unit:"tbsp"},{name:"Sesame oil",quantity:"1",unit:"tbsp"},{name:"Seaweed (gim)",quantity:"2",unit:"sheets"},{name:"Spring onion",quantity:"3",unit:"stalks"},{name:"Salt",quantity:"0.5",unit:"tsp"}], preparation_steps:["Simmer brisket with garlic 40 minutes until tender. Remove and slice.","Keep broth simmering. Season with soy and salt.","Soak rice cakes in cold water 30 minutes.","Add rice cakes to broth. Cook 5-7 minutes until tender.","Make egg garnish: thin omelette, cut into strips.","Toast seaweed and crumble.","Serve in bowls topped with beef, egg strips, seaweed and spring onion.","Drizzle sesame oil."], chef_notes:"The oval shape of the rice cakes symbolises coins — eating them brings wealth in the new year. Rice cakes must be soaked before cooking to prevent them from being too chewy.", serving_suggestions:"Eat on Seollal (Lunar New Year) morning. A bowl makes you one year older according to Korean tradition.", nutrition_estimate:{calories:"345",protein_g:"16",carbohydrates_g:"52",fat_g:"8"}, tags:["New Year","Rice Cakes","Traditional","Lunar New Year"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Budae Jjigae (Army Base Stew)", state:"Korea", cuisine:"Korean", category:"Soups", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:20, total_time_minutes:35, servings:4, short_description:"A uniquely Korean fusion stew born after the Korean War — spam, hot dogs, baked beans and instant ramen combined with gochujang and kimchi. Deeply flavourful and comforting.", ingredients:[{name:"Spam",quantity:"200",unit:"g"},{name:"Hot dogs",quantity:"4",unit:"pieces"},{name:"Baked beans",quantity:"200",unit:"g"},{name:"Kimchi",quantity:"150",unit:"g"},{name:"Instant ramen noodles",quantity:"2",unit:"packs"},{name:"Gochujang",quantity:"2",unit:"tbsp"},{name:"Gochugaru",quantity:"1",unit:"tbsp"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Anchovy stock",quantity:"600",unit:"ml"},{name:"Spring onion",quantity:"4",unit:"stalks"},{name:"Cheddar cheese slice",quantity:"2",unit:"pieces"}], preparation_steps:["Arrange spam, hot dogs, kimchi and baked beans in sections in a wide pot.","Mix gochujang, gochugaru and garlic. Spread in centre.","Pour anchovy stock over everything.","Bring to boil at the table on a portable burner.","Stir sauce into broth.","Add ramen noodles.","Top with cheese slice — let it melt.","Eat communally from the pot."], chef_notes:"Budae jjigae is a living piece of Korean history — born from wartime scarcity and American military surplus. Authentically it should be cooked and eaten at the table communally.", serving_suggestions:"Cook and eat at the table communally. Serve with steamed rice.", nutrition_estimate:{calories:"445",protein_g:"20",carbohydrates_g:"48",fat_g:"18"}, tags:["Fusion","Post-War","Communal","Unique Korean"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },

  // ── SALADS ──────────────────────────────────────────────────────────────────
  { dish_name:"Kongnamul Muchim (Soybean Sprout Salad)", state:"Korea", cuisine:"Korean", category:"Salads", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:5, total_time_minutes:15, servings:4, short_description:"A simple, crunchy Korean soybean sprout salad seasoned with sesame oil, garlic and soy sauce — one of the most essential and beloved Korean banchan.", ingredients:[{name:"Soybean sprouts",quantity:"400",unit:"g"},{name:"Garlic",quantity:"3",unit:"cloves"},{name:"Soy sauce",quantity:"2",unit:"tbsp"},{name:"Sesame oil",quantity:"2",unit:"tbsp"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"},{name:"Gochugaru",quantity:"1",unit:"tsp"},{name:"Spring onion",quantity:"2",unit:"stalks"},{name:"Salt",quantity:"0.5",unit:"tsp"}], preparation_steps:["Blanch soybean sprouts in boiling salted water 2 minutes — keep the lid on.","Drain and cool under cold water.","Squeeze out excess water.","Season with soy sauce, minced garlic, sesame oil and gochugaru.","Toss well.","Top with sesame seeds and spring onion.","Serve at room temperature."], chef_notes:"Never lift the lid while blanching sprouts — the steam creates a fresh, clean flavour. Lifting the lid causes a beany smell. They must remain slightly crunchy.", serving_suggestions:"Serve as an essential banchan alongside all Korean meals.", nutrition_estimate:{calories:"85",protein_g:"5",carbohydrates_g:"6",fat_g:"5"}, tags:["Banchan","Sprouts","Simple","Korean Essential"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Sigeumchi Namul (Korean Spinach Salad)", state:"Korea", cuisine:"Korean", category:"Salads", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:5, total_time_minutes:15, servings:4, short_description:"Blanched spinach seasoned with garlic, sesame oil and soy sauce — delicate, fragrant and an essential component of bibimbap and Korean tables.", ingredients:[{name:"Fresh spinach",quantity:"400",unit:"g"},{name:"Garlic",quantity:"3",unit:"cloves"},{name:"Soy sauce",quantity:"2",unit:"tbsp"},{name:"Sesame oil",quantity:"2",unit:"tbsp"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"},{name:"Salt",quantity:"0.5",unit:"tsp"},{name:"Spring onion",quantity:"2",unit:"stalks"}], preparation_steps:["Blanch spinach in boiling salted water 30 seconds only.","Transfer immediately to ice water to stop cooking and preserve colour.","Squeeze all water out very firmly.","Season with soy sauce, minced garlic and sesame oil.","Toss gently with hands.","Top with sesame seeds and spring onion.","Serve at room temperature."], chef_notes:"30 seconds is maximum for spinach — longer and it becomes slimy. Squeezing spinach thoroughly is essential — watery sigeumchi namul is unacceptable.", serving_suggestions:"Serve as banchan or use as one of the toppings in bibimbap.", nutrition_estimate:{calories:"75",protein_g:"4",carbohydrates_g:"5",fat_g:"5"}, tags:["Spinach","Banchan","Healthy","Korean"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Japchae Salad (Cold Glass Noodle Salad)", state:"Korea", cuisine:"Korean", category:"Salads", difficulty_level:"Easy", prep_time_minutes:20, cook_time_minutes:10, total_time_minutes:30, servings:4, short_description:"A refreshing cold Korean glass noodle salad with cucumber, carrot and sesame dressing — lighter than traditional hot japchae, perfect for summer.", ingredients:[{name:"Glass noodles",quantity:"200",unit:"g"},{name:"Cucumber",quantity:"1",unit:"large"},{name:"Carrot",quantity:"1",unit:"medium"},{name:"Eggs",quantity:"2",unit:"large"},{name:"Soy sauce",quantity:"3",unit:"tbsp"},{name:"Sesame oil",quantity:"2",unit:"tbsp"},{name:"Sugar",quantity:"1",unit:"tbsp"},{name:"Rice vinegar",quantity:"2",unit:"tbsp"},{name:"Garlic",quantity:"2",unit:"cloves"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"}], preparation_steps:["Cook glass noodles, rinse under cold water until completely cold.","Julienne cucumber and carrot into fine strips.","Make thin omelette and cut into strips.","Make dressing: soy sauce, sesame oil, sugar, vinegar and garlic.","Combine noodles, cucumber, carrot and egg strips.","Pour dressing and toss well.","Top with sesame seeds.","Serve cold."], chef_notes:"This salad must be served cold — warm noodles make it mushy. The balance of sweet-sour-salty in the dressing is what makes this dish sing.", serving_suggestions:"Serve chilled as a refreshing summer starter or side dish.", nutrition_estimate:{calories:"265",protein_g:"7",carbohydrates_g:"42",fat_g:"8"}, tags:["Cold Noodles","Summer","Refreshing","Korean"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Oi Muchim (Spicy Cucumber Salad)", state:"Korea", cuisine:"Korean", category:"Salads", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:0, total_time_minutes:15, servings:4, short_description:"A refreshing, fiery Korean cucumber salad with gochugaru, garlic and sesame — crunchy, cool and spicy all at once. The perfect banchan for any Korean meal.", ingredients:[{name:"Korean cucumber",quantity:"3",unit:"medium"},{name:"Gochugaru",quantity:"2",unit:"tbsp"},{name:"Garlic",quantity:"3",unit:"cloves"},{name:"Fish sauce",quantity:"2",unit:"tbsp"},{name:"Rice vinegar",quantity:"1",unit:"tbsp"},{name:"Sesame oil",quantity:"1",unit:"tbsp"},{name:"Sugar",quantity:"1",unit:"tsp"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"},{name:"Spring onion",quantity:"2",unit:"stalks"}], preparation_steps:["Cut cucumber into thin rounds or half-moons.","Salt cucumber and rest 10 minutes. Rinse and squeeze dry.","Mix gochugaru, minced garlic, fish sauce, vinegar, sugar and sesame oil.","Toss cucumber with dressing.","Mix in spring onion.","Top with sesame seeds.","Serve immediately or refrigerate 30 minutes."], chef_notes:"Salting and squeezing the cucumber removes excess moisture that would water down the dressing. Korean cucumbers are thinner and crisper than regular cucumbers.", serving_suggestions:"Serve as banchan — pairs especially well with grilled meat.", nutrition_estimate:{calories:"65",protein_g:"2",carbohydrates_g:"8",fat_g:"3"}, tags:["Cucumber","Spicy","Banchan","Refreshing"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Gaji Namul (Seasoned Eggplant)", state:"Korea", cuisine:"Korean", category:"Salads", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:10, total_time_minutes:20, servings:4, short_description:"Steamed eggplant hand-shredded and seasoned with soy sauce, sesame oil and garlic — a silky, savoury Korean banchan that showcases humble eggplant beautifully.", ingredients:[{name:"Korean eggplant",quantity:"4",unit:"medium"},{name:"Soy sauce",quantity:"2",unit:"tbsp"},{name:"Sesame oil",quantity:"2",unit:"tbsp"},{name:"Garlic",quantity:"3",unit:"cloves"},{name:"Gochugaru",quantity:"1",unit:"tsp"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"},{name:"Spring onion",quantity:"2",unit:"stalks"}], preparation_steps:["Cut eggplant into quarters lengthwise.","Steam 8-10 minutes until completely soft.","Cool slightly. Shred into thin strips by hand — do not use knife.","Season with soy sauce, minced garlic, sesame oil and gochugaru.","Toss gently.","Top with sesame seeds and spring onion.","Serve at room temperature."], chef_notes:"Hand-shredding eggplant creates irregular texture that absorbs seasoning better than knife cuts. The eggplant should be completely soft — undercooked eggplant tastes bitter.", serving_suggestions:"Serve as banchan at room temperature.", nutrition_estimate:{calories:"85",protein_g:"2",carbohydrates_g:"10",fat_g:"5"}, tags:["Eggplant","Banchan","Vegetarian","Korean"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Musaengchae (Spicy Radish Salad)", state:"Korea", cuisine:"Korean", category:"Salads", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:0, total_time_minutes:15, servings:4, short_description:"Finely shredded Korean radish tossed with gochugaru, garlic and sesame oil — vibrantly pink, crunchy and refreshing. An essential banchan and kimchi component.", ingredients:[{name:"Korean radish (mu)",quantity:"400",unit:"g"},{name:"Gochugaru",quantity:"2",unit:"tbsp"},{name:"Fish sauce",quantity:"2",unit:"tbsp"},{name:"Garlic",quantity:"3",unit:"cloves"},{name:"Sugar",quantity:"1",unit:"tsp"},{name:"Sesame oil",quantity:"1",unit:"tbsp"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"},{name:"Spring onion",quantity:"2",unit:"stalks"}], preparation_steps:["Peel radish and cut into fine matchsticks.","Salt radish and rest 10 minutes. Squeeze out moisture.","Mix gochugaru, fish sauce, garlic and sugar.","Add radish to seasoning mixture.","Mix well with hands — the radish will turn pink.","Add sesame oil and spring onion.","Top with sesame seeds.","Serve immediately."], chef_notes:"The radish must be squeezed dry — excess moisture dilutes the vivid pink colour and flavour. Mix with hands to coat every piece evenly.", serving_suggestions:"Serve as a crunchy, refreshing banchan. Also used as a filling in kimbap.", nutrition_estimate:{calories:"65",protein_g:"1",carbohydrates_g:"10",fat_g:"3"}, tags:["Radish","Pink","Banchan","Crunchy"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Jeon Salad (Korean Pancake Salad)", state:"Korea", cuisine:"Korean", category:"Salads", difficulty_level:"Easy", prep_time_minutes:20, cook_time_minutes:15, total_time_minutes:35, servings:4, short_description:"Crispy Korean pancakes sliced and served over fresh greens with a tangy vinegar-soy dressing — a modern Korean salad combining traditional flavours.", ingredients:[{name:"Korean pancakes (pajeon or kimchijeon)",quantity:"2",unit:"pieces"},{name:"Mixed greens",quantity:"150",unit:"g"},{name:"Cucumber",quantity:"1",unit:"medium"},{name:"Carrot",quantity:"1",unit:"medium"},{name:"Soy sauce",quantity:"3",unit:"tbsp"},{name:"Rice vinegar",quantity:"2",unit:"tbsp"},{name:"Sesame oil",quantity:"1",unit:"tbsp"},{name:"Honey",quantity:"1",unit:"tbsp"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"},{name:"Gochugaru",quantity:"1",unit:"tsp"}], preparation_steps:["Make pajeon or kimchijeon pancakes and cut into strips.","Julienne cucumber and carrot.","Make dressing: soy sauce, vinegar, sesame oil, honey and gochugaru.","Arrange greens on plates.","Top with cucumber, carrot and pancake strips.","Drizzle dressing over.","Top with sesame seeds."], chef_notes:"The pancakes should be warm and crispy — add them to the salad just before serving to prevent softening.", serving_suggestions:"Serve as a light lunch or modern Korean fusion starter.", nutrition_estimate:{calories:"245",protein_g:"8",carbohydrates_g:"32",fat_g:"10"}, tags:["Fusion","Pancake","Modern Korean","Light"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Doraji Namul (Bellflower Root Salad)", state:"Korea", cuisine:"Korean", category:"Salads", difficulty_level:"Medium", prep_time_minutes:30, cook_time_minutes:5, total_time_minutes:35, servings:4, short_description:"A traditional Korean salad of bellflower root — slightly bitter, crunchy and distinctively flavoured, seasoned with soy, garlic and sesame. A beloved royal court food.", ingredients:[{name:"Dried bellflower root (doraji)",quantity:"150",unit:"g"},{name:"Soy sauce",quantity:"2",unit:"tbsp"},{name:"Sesame oil",quantity:"2",unit:"tbsp"},{name:"Garlic",quantity:"3",unit:"cloves"},{name:"Sugar",quantity:"1",unit:"tsp"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"},{name:"Salt",quantity:"1",unit:"tsp"},{name:"Gochugaru",quantity:"1",unit:"tsp"}], preparation_steps:["Soak dried bellflower root in water 2 hours.","Rinse well. Salt and knead to remove bitterness.","Rinse again several times.","Blanch 3 minutes in boiling water. Drain.","Season with soy sauce, garlic, sesame oil, sugar and gochugaru.","Toss well with hands.","Top with sesame seeds.","Serve at room temperature."], chef_notes:"Kneading with salt removes the natural bitterness of bellflower root. Multiple rinsing is essential. Doraji is prized for its medicinal properties in Korean culture.", serving_suggestions:"Serve as traditional banchan. An essential component of royal court cuisine.", nutrition_estimate:{calories:"95",protein_g:"3",carbohydrates_g:"12",fat_g:"4"}, tags:["Bellflower Root","Traditional","Royal Court","Korean"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Cheongpo Muk Muchim (Mung Bean Jelly Salad)", state:"Korea", cuisine:"Korean", category:"Salads", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:0, total_time_minutes:15, servings:4, short_description:"Silky mung bean jelly cut into strips and tossed with soy sauce, sesame oil and vegetables — a uniquely Korean dish with a delicate, wobbly texture.", ingredients:[{name:"Mung bean jelly (cheongpo muk)",quantity:"400",unit:"g"},{name:"Soy sauce",quantity:"3",unit:"tbsp"},{name:"Sesame oil",quantity:"2",unit:"tbsp"},{name:"Gochugaru",quantity:"1",unit:"tbsp"},{name:"Garlic",quantity:"2",unit:"cloves"},{name:"Spring onion",quantity:"3",unit:"stalks"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"},{name:"Sugar",quantity:"1",unit:"tsp"}], preparation_steps:["Cut mung bean jelly into strips or cubes.","Mix soy sauce, sesame oil, gochugaru, garlic and sugar.","Pour dressing over jelly.","Add spring onion and toss very gently.","Top with sesame seeds.","Serve immediately — jelly absorbs liquid quickly."], chef_notes:"Mung bean jelly is delicate — toss very gently to avoid breaking. Serve immediately after dressing as the jelly absorbs the sauce and changes texture over time.", serving_suggestions:"Serve as a unique banchan or light snack.", nutrition_estimate:{calories:"105",protein_g:"3",carbohydrates_g:"14",fat_g:"5"}, tags:["Mung Bean Jelly","Unique","Silky","Korean"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },

  // ── MAIN COURSES ────────────────────────────────────────────────────────────
  { dish_name:"Bibimbap (Mixed Rice Bowl)", state:"Korea", cuisine:"Korean", category:"Main Courses", difficulty_level:"Medium", prep_time_minutes:45, cook_time_minutes:30, total_time_minutes:75, servings:4, short_description:"Korea's most iconic dish — a bowl of warm rice topped with sautéed vegetables, raw egg and gochujang, mixed vigorously before eating. A complete, nutritious and beautiful meal.", ingredients:[{name:"Steamed rice",quantity:"600",unit:"g"},{name:"Spinach",quantity:"150",unit:"g"},{name:"Carrot",quantity:"1",unit:"large"},{name:"Zucchini",quantity:"1",unit:"medium"},{name:"Shiitake mushrooms",quantity:"6",unit:"pieces"},{name:"Bean sprouts",quantity:"150",unit:"g"},{name:"Beef mince",quantity:"200",unit:"g"},{name:"Gochujang",quantity:"4",unit:"tbsp"},{name:"Eggs",quantity:"4",unit:"large"},{name:"Sesame oil",quantity:"3",unit:"tbsp"},{name:"Soy sauce",quantity:"2",unit:"tbsp"},{name:"Garlic",quantity:"4",unit:"cloves"}], preparation_steps:["Prepare each vegetable separately: blanch spinach, sauté carrot, zucchini and mushrooms individually with garlic and soy sauce.","Season bean sprouts with sesame oil and salt.","Stir-fry beef with soy sauce, garlic and sesame oil.","Mix gochujang sauce with sesame oil and sugar.","Place hot rice in dolsot (stone pot) or bowl.","Arrange vegetables and beef in separate sections over rice.","Place raw egg yolk in centre (or fried egg on top).","Add gochujang sauce. Mix vigorously before eating."], chef_notes:"Each ingredient must be prepared and seasoned individually — this is the time-consuming but essential technique. The dolsot version creates crispy rice at the bottom (nurungji) which is the prize.", serving_suggestions:"Mix everything vigorously at the table. The stone pot version creates crispy rice at the bottom.", nutrition_estimate:{calories:"485",protein_g:"22",carbohydrates_g:"68",fat_g:"14"}, tags:["Bibimbap","Iconic","Complete Meal","Korean"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Korean BBQ Beef (Bulgogi)", state:"Korea", cuisine:"Korean", category:"Main Courses", difficulty_level:"Easy", prep_time_minutes:30, cook_time_minutes:10, total_time_minutes:40, servings:4, short_description:"Korea's most internationally beloved dish — paper-thin slices of beef marinated in sweet soy, pear and garlic, grilled until caramelised and smoky. Elegant in its simplicity.", ingredients:[{name:"Beef sirloin",quantity:"600",unit:"g"},{name:"Asian pear or kiwi",quantity:"1",unit:"piece"},{name:"Soy sauce",quantity:"4",unit:"tbsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Sesame oil",quantity:"2",unit:"tbsp"},{name:"Garlic",quantity:"6",unit:"cloves"},{name:"Ginger",quantity:"0.5",unit:"inch"},{name:"Spring onion",quantity:"4",unit:"stalks"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"},{name:"Black pepper",quantity:"0.5",unit:"tsp"}], preparation_steps:["Freeze beef 1 hour for easier slicing. Slice paper thin.","Grate pear, garlic and ginger.","Mix soy sauce, sugar, sesame oil, pear, garlic, ginger and pepper.","Marinate beef minimum 30 minutes, ideally overnight.","Grill on very hot grill or BBQ in small batches.","Do not crowd — beef should sizzle and char at edges.","Cook 1-2 minutes per side only.","Serve with spring onion and sesame seeds."], chef_notes:"Asian pear contains enzymes that tenderise the beef — do not skip it. Paper-thin slicing is essential. Bulgogi cooks in seconds on high heat.", serving_suggestions:"Wrap in lettuce leaves with rice, garlic and ssamjang. Serve with banchan.", nutrition_estimate:{calories:"345",protein_g:"30",carbohydrates_g:"14",fat_g:"18"}, tags:["BBQ","Bulgogi","Beef","Korean BBQ"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Galbi (Korean Short Ribs)", state:"Korea", cuisine:"Korean", category:"Main Courses", difficulty_level:"Medium", prep_time_minutes:60, cook_time_minutes:15, total_time_minutes:75, servings:4, short_description:"Flanken-cut beef short ribs marinated overnight in soy, pear and sesame — the jewel of Korean BBQ culture. Impossibly tender with deep caramelised flavour.", ingredients:[{name:"Beef short ribs (flanken cut)",quantity:"800",unit:"g"},{name:"Asian pear",quantity:"1",unit:"large"},{name:"Soy sauce",quantity:"6",unit:"tbsp"},{name:"Sugar",quantity:"3",unit:"tbsp"},{name:"Sesame oil",quantity:"2",unit:"tbsp"},{name:"Garlic",quantity:"8",unit:"cloves"},{name:"Ginger",quantity:"1",unit:"inch"},{name:"Onion",quantity:"1",unit:"large"},{name:"Black pepper",quantity:"1",unit:"tsp"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"}], preparation_steps:["Score ribs in a crosshatch pattern to allow marinade penetration.","Soak in cold water 1 hour to remove blood.","Blend pear, onion, garlic, ginger and soy sauce.","Add sugar, sesame oil and pepper.","Marinate ribs overnight minimum — 24 hours is ideal.","Grill over hot charcoal or grill pan.","Cook 4-5 minutes per side until charred and caramelised.","Serve with scissors for cutting at the table."], chef_notes:"The overnight marinade is non-negotiable — galbi needs time for the enzymes in pear to work and the flavours to penetrate the thick ribs. Charcoal grilling creates the essential smoky flavour.", serving_suggestions:"Serve with scissors to cut at the table, wrapped in lettuce with rice and ssamjang.", nutrition_estimate:{calories:"485",protein_g:"34",carbohydrates_g:"16",fat_g:"32"}, tags:["Short Ribs","Korean BBQ","Overnight Marinade","Special Occasion"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Dakgalbi (Spicy Stir-Fried Chicken)", state:"Korea", cuisine:"Korean", category:"Main Courses", difficulty_level:"Easy", prep_time_minutes:20, cook_time_minutes:20, total_time_minutes:40, servings:4, short_description:"A fiery, interactive Korean dish of chicken and tteok stir-fried in gochujang sauce on a cast iron griddle at the table — bold, spicy and deeply satisfying.", ingredients:[{name:"Chicken thigh",quantity:"600",unit:"g"},{name:"Tteok rice cakes",quantity:"150",unit:"g"},{name:"Sweet potato",quantity:"1",unit:"medium"},{name:"Cabbage",quantity:"200",unit:"g"},{name:"Gochujang",quantity:"4",unit:"tbsp"},{name:"Gochugaru",quantity:"2",unit:"tbsp"},{name:"Soy sauce",quantity:"2",unit:"tbsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Sesame oil",quantity:"1",unit:"tbsp"},{name:"Garlic",quantity:"5",unit:"cloves"},{name:"Ginger",quantity:"0.5",unit:"inch"}], preparation_steps:["Cut chicken into bite-sized pieces.","Make marinade: gochujang, gochugaru, soy sauce, sugar, garlic, ginger and sesame oil.","Marinate chicken 30 minutes.","Stir-fry chicken in cast iron pan on high heat.","Add tteok and sweet potato.","Add cabbage and any remaining marinade.","Stir-fry until everything is coated and cooked.","Finish with sesame oil drizzle."], chef_notes:"Dakgalbi is traditionally cooked on a large cast iron griddle at the table. At the end, make fried rice with the leftover sauce — this is the best part.", serving_suggestions:"Serve on a communal cast iron pan at the table. Add noodles or fried rice at the end.", nutrition_estimate:{calories:"385",protein_g:"32",carbohydrates_g:"36",fat_g:"14"}, tags:["Spicy Chicken","Interactive","Korean","Gochujang"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Haemul Pajeon (Seafood Pancake)", state:"Korea", cuisine:"Korean", category:"Main Courses", difficulty_level:"Medium", prep_time_minutes:20, cook_time_minutes:20, total_time_minutes:40, servings:4, short_description:"A large, crispy Korean seafood pancake loaded with squid, prawns and spring onion — a beloved Korean pub food that pairs perfectly with makgeolli rice wine.", ingredients:[{name:"Squid",quantity:"150",unit:"g"},{name:"Prawns",quantity:"150",unit:"g"},{name:"Spring onion",quantity:"150",unit:"g"},{name:"Flour",quantity:"150",unit:"g"},{name:"Rice flour",quantity:"50",unit:"g"},{name:"Egg",quantity:"2",unit:"large"},{name:"Cold water",quantity:"200",unit:"ml"},{name:"Salt",quantity:"0.5",unit:"tsp"},{name:"Oil",quantity:"5",unit:"tbsp"},{name:"Soy sauce",quantity:"3",unit:"tbsp"},{name:"Rice vinegar",quantity:"2",unit:"tbsp"}], preparation_steps:["Mix flours, eggs and cold water into smooth batter.","Clean and slice seafood.","Cut spring onions into long pieces.","Heat generous oil in large pan over high heat.","Pour batter. Arrange spring onions over entire surface.","Place seafood on top, pressing down.","Cook 5-6 minutes until edges are crispy.","Flip carefully. Cook 4 more minutes.","Cut into squares and serve with dipping sauce."], chef_notes:"A generous amount of oil is what creates the crispy edges — do not skimp. The pancake should be thin enough to be crispy, not thick and doughy.", serving_suggestions:"Serve hot with soy-vinegar dipping sauce. Pairs perfectly with makgeolli.", nutrition_estimate:{calories:"345",protein_g:"22",carbohydrates_g:"38",fat_g:"12"}, tags:["Seafood","Pancake","Makgeolli","Korean Pub"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Kimbap (Korean Rice Rolls)", state:"Korea", cuisine:"Korean", category:"Main Courses", difficulty_level:"Medium", prep_time_minutes:45, cook_time_minutes:20, total_time_minutes:65, servings:4, short_description:"Korea's beloved rolled rice dish — seasoned rice, vegetables, egg and protein wrapped in toasted seaweed. Korea's answer to sushi, with a distinct flavour all its own.", ingredients:[{name:"Sushi rice",quantity:"400",unit:"g"},{name:"Nori seaweed sheets",quantity:"6",unit:"pieces"},{name:"Spinach",quantity:"150",unit:"g"},{name:"Carrot",quantity:"1",unit:"large"},{name:"Pickled radish (danmuji)",quantity:"150",unit:"g"},{name:"Eggs",quantity:"3",unit:"large"},{name:"Sesame oil",quantity:"3",unit:"tbsp"},{name:"Salt",quantity:"1",unit:"tsp"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"},{name:"Ham or tuna",quantity:"150",unit:"g"}], preparation_steps:["Season cooked rice with sesame oil and salt.","Blanch and season spinach. Stir-fry carrot strips.","Make thin egg omelette and cut into strips.","Lay nori on bamboo mat.","Spread rice thinly over nori.","Place fillings in a line across the centre.","Roll tightly using bamboo mat.","Rub outside with sesame oil.","Slice with sharp oiled knife into rounds."], chef_notes:"Kimbap is seasoned with sesame oil, not vinegar like Japanese sushi — this is the key difference. The outside should be glossy with sesame oil. Roll very tightly.", serving_suggestions:"Serve sliced with danmuji (yellow pickled radish) and kimchi.", nutrition_estimate:{calories:"365",protein_g:"14",carbohydrates_g:"56",fat_g:"10"}, tags:["Rice Roll","Lunch Box","Korean Classic","Sesame"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Jeyuk Bokkeum (Spicy Pork Stir-Fry)", state:"Korea", cuisine:"Korean", category:"Main Courses", difficulty_level:"Easy", prep_time_minutes:20, cook_time_minutes:15, total_time_minutes:35, servings:4, short_description:"Fiery stir-fried pork belly with gochujang, ginger and onion — one of Korea's most popular everyday dishes, eaten wrapped in lettuce with rice.", ingredients:[{name:"Pork belly slices",quantity:"600",unit:"g"},{name:"Gochujang",quantity:"3",unit:"tbsp"},{name:"Gochugaru",quantity:"2",unit:"tbsp"},{name:"Soy sauce",quantity:"2",unit:"tbsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Sesame oil",quantity:"1",unit:"tbsp"},{name:"Garlic",quantity:"5",unit:"cloves"},{name:"Ginger",quantity:"0.5",unit:"inch"},{name:"Onion",quantity:"1",unit:"large"},{name:"Spring onion",quantity:"3",unit:"stalks"}], preparation_steps:["Slice pork belly into thin pieces.","Mix gochujang, gochugaru, soy sauce, sugar, garlic, ginger and sesame oil.","Marinate pork 20 minutes.","Stir-fry pork over high heat until cooked and caramelised.","Add onion slices.","Cook until onion is soft and sauce coats everything.","Garnish with spring onion and sesame seeds.","Serve with rice and lettuce."], chef_notes:"High heat is essential — jeyuk bokkeum should have some caramelisation and slight charring. The pork fat should render and crisp slightly.", serving_suggestions:"Serve wrapped in lettuce with rice and garlic slices.", nutrition_estimate:{calories:"425",protein_g:"22",carbohydrates_g:"14",fat_g:"32"}, tags:["Pork Belly","Spicy","Stir-Fry","Everyday Korean"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Dak Bokkeum Tang (Spicy Braised Chicken)", state:"Korea", cuisine:"Korean", category:"Main Courses", difficulty_level:"Medium", prep_time_minutes:20, cook_time_minutes:40, total_time_minutes:60, servings:4, short_description:"A bold, hearty Korean braised chicken with potatoes and gochujang — slowly simmered until the chicken is fall-off-the-bone tender and deeply flavoured.", ingredients:[{name:"Whole chicken pieces",quantity:"800",unit:"g"},{name:"Potatoes",quantity:"2",unit:"large"},{name:"Onion",quantity:"1",unit:"large"},{name:"Carrot",quantity:"1",unit:"large"},{name:"Gochujang",quantity:"3",unit:"tbsp"},{name:"Gochugaru",quantity:"2",unit:"tbsp"},{name:"Soy sauce",quantity:"3",unit:"tbsp"},{name:"Sugar",quantity:"1",unit:"tbsp"},{name:"Garlic",quantity:"6",unit:"cloves"},{name:"Ginger",quantity:"0.5",unit:"inch"},{name:"Sesame oil",quantity:"1",unit:"tbsp"}], preparation_steps:["Blanch chicken in boiling water 3 minutes. Rinse.","Mix gochujang, gochugaru, soy sauce, sugar, garlic and ginger.","Brown chicken in oil.","Add sauce and enough water to half cover.","Add potatoes, onion and carrot.","Braise covered 30 minutes until chicken is cooked.","Remove lid and reduce sauce until thick.","Drizzle sesame oil and garnish with spring onion."], chef_notes:"Blanching chicken first removes impurities and excess fat, giving a cleaner flavour. The sauce should be thick enough to glaze the chicken at the end.", serving_suggestions:"Serve with steamed rice. The braising sauce over rice is delicious.", nutrition_estimate:{calories:"365",protein_g:"34",carbohydrates_g:"22",fat_g:"16"}, tags:["Braised Chicken","Spicy","Hearty","Korean"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Samgyeopsal (Grilled Pork Belly)", state:"Korea", cuisine:"Korean", category:"Main Courses", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:15, total_time_minutes:25, servings:4, short_description:"Korea's most popular BBQ dish — thick slices of uncured pork belly grilled at the table and wrapped in lettuce with garlic, ssamjang and kimchi.", ingredients:[{name:"Thick pork belly slices",quantity:"800",unit:"g"},{name:"Garlic",quantity:"1",unit:"head"},{name:"Green chilli",quantity:"4",unit:"pieces"},{name:"Kimchi",quantity:"200",unit:"g"},{name:"Ssamjang paste",quantity:"6",unit:"tbsp"},{name:"Lettuce leaves",quantity:"20",unit:"pieces"},{name:"Perilla leaves",quantity:"20",unit:"pieces"},{name:"Sesame oil",quantity:"2",unit:"tbsp"},{name:"Salt",quantity:"1",unit:"tsp"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"}], preparation_steps:["Slice whole garlic cloves and slice green chilli.","Heat cast iron pan or grill until smoking.","Place pork belly directly on grill without any marinade.","Grill 3-4 minutes per side until crispy and golden.","Use scissors to cut into bite-sized pieces at the table.","Make salt-sesame dipping sauce.","Wrap: place rice and pork in lettuce with garlic, ssamjang and kimchi.","Eat as a single bite."], chef_notes:"Samgyeopsal has no marinade — the quality of the pork is everything. The scissors technique at the table is essential for cutting the pork while hot. Ssamjang is the indispensable dipping paste.", serving_suggestions:"Grill at the table on a cast iron pan. Set up wrapping station with lettuce, perilla, garlic, chilli, ssamjang and kimchi.", nutrition_estimate:{calories:"520",protein_g:"26",carbohydrates_g:"6",fat_g:"44"}, tags:["Korean BBQ","Pork Belly","Grilled","Interactive"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },

  // ── DESSERTS ────────────────────────────────────────────────────────────────
  { dish_name:"Bingsu (Korean Shaved Ice)", state:"Korea", cuisine:"Korean", category:"Desserts", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:0, total_time_minutes:15, servings:4, short_description:"Korea's beloved summer dessert — finely shaved milk ice topped with sweet red beans, rice cakes, condensed milk and fruit. Light as snow and irresistibly refreshing.", ingredients:[{name:"Milk ice blocks",quantity:"4",unit:"large"},{name:"Sweet red beans (pat)",quantity:"200",unit:"g"},{name:"Tteok rice cakes",quantity:"100",unit:"g"},{name:"Condensed milk",quantity:"6",unit:"tbsp"},{name:"Fresh fruit",quantity:"200",unit:"g"},{name:"Matcha powder",quantity:"2",unit:"tsp"},{name:"Corn flakes",quantity:"4",unit:"tbsp"},{name:"Ice cream scoop",quantity:"2",unit:"pieces"}], preparation_steps:["Shave milk ice blocks using bingsu machine or blender.","Cook sweet red beans with sugar until soft.","Cook tteok rice cakes until soft and chewy.","Mound shaved ice high in bowls.","Top with red beans, tteok and fruit.","Drizzle with condensed milk.","Add ice cream scoop.","Dust with matcha if desired."], chef_notes:"Milk ice (not water ice) creates the characteristic fluffy, snow-like texture that melts instantly on the tongue. The toppings should completely bury the ice for authentic bingsu.", serving_suggestions:"Serve immediately in a large bowl to share. The ice melts quickly.", nutrition_estimate:{calories:"285",protein_g:"6",carbohydrates_g:"56",fat_g:"6"}, tags:["Shaved Ice","Summer","Beloved","Korean Dessert"], img:"https://images.unsplash.com/photo-1558024920-b41e1887dc32?w=400&q=80" },
  { dish_name:"Hotteok (Sweet Filled Pancakes)", state:"Korea", cuisine:"Korean", category:"Desserts", difficulty_level:"Medium", prep_time_minutes:60, cook_time_minutes:20, total_time_minutes:80, servings:8, short_description:"Korea's most beloved winter street food — yeasted dough pancakes filled with brown sugar, cinnamon, nuts and honey, pressed flat and pan-fried until crispy outside with a molten sweet centre.", ingredients:[{name:"Flour",quantity:"300",unit:"g"},{name:"Dry yeast",quantity:"1",unit:"tsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Salt",quantity:"0.5",unit:"tsp"},{name:"Warm water",quantity:"220",unit:"ml"},{name:"Brown sugar",quantity:"100",unit:"g"},{name:"Cinnamon",quantity:"2",unit:"tsp"},{name:"Chopped peanuts",quantity:"50",unit:"g"},{name:"Honey",quantity:"2",unit:"tbsp"},{name:"Oil",quantity:"3",unit:"tbsp"}], preparation_steps:["Mix flour, yeast, sugar, salt and warm water. Knead 10 minutes.","Rest dough 1 hour until doubled.","Mix brown sugar, cinnamon, peanuts and honey for filling.","Divide dough into 8 balls.","Flatten each ball, add filling, gather edges and seal.","Place sealed-side down in oiled pan.","Press flat with a spatula immediately.","Cook 3 minutes per side until golden.","Eat immediately — the filling is molten."], chef_notes:"Press the hotteok flat immediately after placing in the pan — this creates the characteristic disc shape. The filling will be dangerously hot molten sugar — warn before eating.", serving_suggestions:"Eat immediately while the filling is still molten. Classic winter street food.", nutrition_estimate:{calories:"285",protein_g:"5",carbohydrates_g:"52",fat_g:"7"}, tags:["Street Food","Winter","Filled Pancake","Sweet"], img:"https://images.unsplash.com/photo-1563805042-7684c019e1cb?w=400&q=80" },
  { dish_name:"Sikhye (Sweet Rice Punch)", state:"Korea", cuisine:"Korean", category:"Desserts", difficulty_level:"Medium", prep_time_minutes:20, cook_time_minutes:30, total_time_minutes:480, servings:8, short_description:"Korea's ancient traditional sweet rice punch — a mildly sweet, amber-coloured fermented rice drink with floating rice grains and pine nuts. Served cold at every Korean celebration.", ingredients:[{name:"Cooked rice",quantity:"200",unit:"g"},{name:"Malt barley powder (yeotgireum)",quantity:"100",unit:"g"},{name:"Water",quantity:"2",unit:"litres"},{name:"Sugar",quantity:"150",unit:"g"},{name:"Ginger",quantity:"2",unit:"inch"},{name:"Pine nuts",quantity:"4",unit:"tbsp"},{name:"Dates",quantity:"4",unit:"pieces"}], preparation_steps:["Dissolve malt barley powder in warm water. Let sit 30 minutes. Strain.","Add cooked rice to malt liquid.","Keep warm at 60°C for 4-6 hours until rice grains float.","Skim off floating rice and reserve.","Add sugar and ginger to liquid. Bring to boil.","Simmer 15 minutes. Cool completely.","Serve cold with floating rice grains and pine nuts."], chef_notes:"The enzymes in malt barley convert rice starch to sugar during the warming period. The temperature must stay around 60°C — too hot kills enzymes, too cold and fermentation doesn't occur.", serving_suggestions:"Serve very cold in traditional Korean bowls with pine nuts and dates as garnish.", nutrition_estimate:{calories:"185",protein_g:"2",carbohydrates_g:"42",fat_g:"2"}, tags:["Traditional Drink","Fermented","Celebration","Korean"], img:"https://images.unsplash.com/photo-1558024920-b41e1887dc32?w=400&q=80" },
  { dish_name:"Yakgwa (Honey Cookies)", state:"Korea", cuisine:"Korean", category:"Desserts", difficulty_level:"Hard", prep_time_minutes:30, cook_time_minutes:30, total_time_minutes:60, servings:20, short_description:"Korea's most traditional confection — crispy deep-fried wheat cookies soaked in honey and ginger syrup, decorated with pine nuts. A Joseon Dynasty royal court sweet.", ingredients:[{name:"Flour",quantity:"300",unit:"g"},{name:"Sesame oil",quantity:"4",unit:"tbsp"},{name:"Honey",quantity:"100",unit:"ml"},{name:"Ginger juice",quantity:"2",unit:"tbsp"},{name:"Soju or rice wine",quantity:"3",unit:"tbsp"},{name:"Extra honey for soaking",quantity:"200",unit:"ml"},{name:"Water",quantity:"100",unit:"ml"},{name:"Pine nuts",quantity:"4",unit:"tbsp"},{name:"Oil for frying",quantity:"2",unit:"cups"}], preparation_steps:["Mix flour with sesame oil until crumbly.","Add honey, ginger juice and soju. Mix minimally.","Roll dough 7mm thick. Cut into shapes.","Press pattern on top with fork or mould.","Deep fry at 140°C (very low heat) until light golden — 15 minutes.","The low temperature ensures even cooking through.","Make soaking syrup: honey, water and ginger — simmer until slightly thick.","Soak fried cookies in warm syrup 30 minutes.","Drain and decorate with pine nuts."], chef_notes:"Yakgwa must be fried at very low temperature — 140°C. High heat makes them dark outside but raw inside. The slow soak in honey syrup gives them their characteristic glossy, deeply flavoured coating.", serving_suggestions:"Serve as traditional Korean confectionery. Keeps for several weeks.", nutrition_estimate:{calories:"185",protein_g:"2",carbohydrates_g:"28",fat_g:"8"}, tags:["Royal Court","Honey Cookie","Traditional","Korean Confectionery"], img:"https://images.unsplash.com/photo-1563805042-7684c019e1cb?w=400&q=80" },
  { dish_name:"Tteok (Rice Cake Varieties)", state:"Korea", cuisine:"Korean", category:"Desserts", difficulty_level:"Hard", prep_time_minutes:30, cook_time_minutes:30, total_time_minutes:60, servings:8, short_description:"Korean rice cakes — steamed glutinous rice pounded and shaped into beautiful forms. The foundation of Korean confectionery, eaten at celebrations and ceremonies.", ingredients:[{name:"Glutinous rice flour",quantity:"400",unit:"g"},{name:"Water",quantity:"200",unit:"ml"},{name:"Sugar",quantity:"80",unit:"g"},{name:"Salt",quantity:"0.5",unit:"tsp"},{name:"Red bean paste",quantity:"200",unit:"g"},{name:"Food colouring",quantity:"2",unit:"tsp"},{name:"Pine nuts",quantity:"3",unit:"tbsp"},{name:"Sesame seeds",quantity:"3",unit:"tbsp"}], preparation_steps:["Mix rice flour with salt and warm water.","Steam the dough 20 minutes.","Remove and pound while hot until smooth and elastic.","Divide and colour portions with natural colours.","Fill portions with red bean paste.","Shape into traditional forms: round, cylindrical or flower-shaped.","Roll in sesame seeds or pine nuts.","Coat in oil to prevent sticking."], chef_notes:"Tteok must be eaten the same day — it hardens quickly. Pounding while hot is the traditional technique that creates the characteristic chewy texture.", serving_suggestions:"Serve as part of Korean dessert spread at celebrations and ceremonies.", nutrition_estimate:{calories:"285",protein_g:"4",carbohydrates_g:"56",fat_g:"5"}, tags:["Rice Cake","Traditional","Ceremony","Korean"], img:"https://images.unsplash.com/photo-1558024920-b41e1887dc32?w=400&q=80" },
  { dish_name:"Sujeonggwa (Cinnamon Persimmon Punch)", state:"Korea", cuisine:"Korean", category:"Desserts", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:30, total_time_minutes:240, servings:8, short_description:"A spicy, warming Korean punch of cinnamon and ginger, served chilled with dried persimmon and pine nuts — an ancient Korean beverage drunk at Lunar New Year.", ingredients:[{name:"Cinnamon sticks",quantity:"5",unit:"pieces"},{name:"Ginger",quantity:"100",unit:"g"},{name:"Water",quantity:"2",unit:"litres"},{name:"Sugar",quantity:"150",unit:"g"},{name:"Dried persimmon (gotgam)",quantity:"4",unit:"pieces"},{name:"Pine nuts",quantity:"4",unit:"tbsp"}], preparation_steps:["Simmer cinnamon sticks in water 30 minutes.","Separately simmer sliced ginger in water 20 minutes.","Strain both. Combine.","Add sugar and stir until dissolved.","Add whole dried persimmons and soak 3 hours.","Refrigerate until very cold.","Serve persimmon in the punch with pine nuts floating on top."], chef_notes:"Sujeonggwa should be very cold — warm sujeonggwa loses its refreshing quality. The persimmon softens beautifully in the punch over 3 hours and absorbs the cinnamon-ginger flavour.", serving_suggestions:"Serve very cold in traditional Korean bowls. Serve the persimmon alongside.", nutrition_estimate:{calories:"145",protein_g:"1",carbohydrates_g:"34",fat_g:"1"}, tags:["Traditional Punch","Cinnamon","New Year","Korean Beverage"], img:"https://images.unsplash.com/photo-1558024920-b41e1887dc32?w=400&q=80" },
  { dish_name:"Bungeoppang (Fish-Shaped Waffles)", state:"Korea", cuisine:"Korean", category:"Desserts", difficulty_level:"Medium", prep_time_minutes:20, cook_time_minutes:20, total_time_minutes:40, servings:8, short_description:"Korea's iconic fish-shaped waffle filled with sweet red bean paste — a beloved winter street food with a crispy waffle exterior and warm, sweet filling.", ingredients:[{name:"Flour",quantity:"200",unit:"g"},{name:"Baking powder",quantity:"1",unit:"tsp"},{name:"Sugar",quantity:"40",unit:"g"},{name:"Salt",quantity:"0.25",unit:"tsp"},{name:"Eggs",quantity:"2",unit:"large"},{name:"Milk",quantity:"200",unit:"ml"},{name:"Oil",quantity:"2",unit:"tbsp"},{name:"Sweet red bean paste",quantity:"300",unit:"g"}], preparation_steps:["Mix flour, baking powder, sugar and salt.","Whisk in eggs, milk and oil into smooth batter.","Heat bungeoppang (fish waffle) mould until very hot. Brush with oil.","Fill one side half with batter.","Add generous spoon of red bean paste in centre.","Cover with more batter.","Close mould and cook 3 minutes per side.","Unmould and serve immediately."], chef_notes:"The mould must be very hot for crispy waffles. Bungeoppang eaten fresh from the street cart is incomparable — the crispy outside and hot bean paste inside is the ideal contrast.", serving_suggestions:"Eat piping hot immediately from the mould — the crispy exterior softens quickly.", nutrition_estimate:{calories:"195",protein_g:"5",carbohydrates_g:"34",fat_g:"5"}, tags:["Fish Waffle","Street Food","Winter","Red Bean"], img:"https://images.unsplash.com/photo-1563805042-7684c019e1cb?w=400&q=80" },
  { dish_name:"Dasik (Korean Tea Cookies)", state:"Korea", cuisine:"Korean", category:"Desserts", difficulty_level:"Medium", prep_time_minutes:30, cook_time_minutes:0, total_time_minutes:30, servings:16, short_description:"Elegant no-bake Korean tea cookies pressed in beautiful wooden moulds — made from rice flour, matcha or sesame with honey. Delicate, fragrant and a true Korean art form.", ingredients:[{name:"Rice flour",quantity:"200",unit:"g"},{name:"Honey",quantity:"4",unit:"tbsp"},{name:"Sesame seeds (toasted and ground)",quantity:"100",unit:"g"},{name:"Matcha powder",quantity:"2",unit:"tbsp"},{name:"Gochugaru (mild)",quantity:"1",unit:"tbsp"},{name:"Cinnamon",quantity:"1",unit:"tsp"},{name:"Salt",quantity:"0.25",unit:"tsp"}], preparation_steps:["Divide rice flour into portions.","Mix one portion with ground sesame seeds and honey.","Mix another with matcha and honey.","Mix third with cinnamon and honey.","Knead each until it holds shape when pressed.","Press firmly into traditional dasik moulds.","Unmould carefully.","Serve on a traditional Korean platter."], chef_notes:"Dasik is pressed art — the wooden moulds create intricate patterns. The dough must be just moist enough to hold the mould impression without being sticky. These are served at tea ceremonies.", serving_suggestions:"Serve with traditional Korean tea. Arrange on a lacquer platter for formal occasions.", nutrition_estimate:{calories:"125",protein_g:"3",carbohydrates_g:"22",fat_g:"3"}, tags:["Tea Cookie","No-Bake","Royal Court","Art Form"], img:"https://images.unsplash.com/photo-1563805042-7684c019e1cb?w=400&q=80" },
  { dish_name:"Gyeongdan (Glutinous Rice Balls)", state:"Korea", cuisine:"Korean", category:"Desserts", difficulty_level:"Easy", prep_time_minutes:30, cook_time_minutes:15, total_time_minutes:45, servings:6, short_description:"Soft, chewy glutinous rice balls coated in toasted sesame seeds, bean powder or coconut — Korea's version of tangyuan or mochi, eaten at Dongji (winter solstice).", ingredients:[{name:"Glutinous rice flour",quantity:"200",unit:"g"},{name:"Warm water",quantity:"150",unit:"ml"},{name:"Red bean paste",quantity:"150",unit:"g"},{name:"Toasted sesame seeds",quantity:"80",unit:"g"},{name:"Sweetened bean powder",quantity:"80",unit:"g"},{name:"Desiccated coconut",quantity:"50",unit:"g"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Salt",quantity:"0.25",unit:"tsp"}], preparation_steps:["Mix rice flour with warm water and sugar. Knead until smooth.","Divide into small balls. Flatten and fill with red bean paste.","Seal well and roll back into balls.","Boil in water until they float, then 2 more minutes.","Transfer to cold water briefly.","Roll each ball in different coatings: sesame, bean powder or coconut.","Arrange on plate showing all three varieties."], chef_notes:"Three different coatings make gyeongdan visually beautiful and offer different flavour experiences. The rice balls should be eaten the same day they are made.", serving_suggestions:"Serve in three varieties on a platter for visual impact.", nutrition_estimate:{calories:"165",protein_g:"4",carbohydrates_g:"30",fat_g:"4"}, tags:["Rice Balls","Winter Solstice","Traditional","Korean"], img:"https://images.unsplash.com/photo-1558024920-b41e1887dc32?w=400&q=80" },

  { dish_name:"Naengmyeon (Cold Buckwheat Noodles)", state:"Korea", cuisine:"Korean", category:"Main Courses", difficulty_level:"Medium", prep_time_minutes:30, cook_time_minutes:30, total_time_minutes:60, servings:4, short_description:"Korea's iconic cold noodle dish — chewy buckwheat noodles in an icy beef broth topped with cucumber, pear, boiled egg and mustard. A Pyongyang classic eaten on the hottest days.", ingredients:[{name:"Buckwheat noodles (naengmyeon)",quantity:"400",unit:"g"},{name:"Beef brisket",quantity:"300",unit:"g"},{name:"Cucumber",quantity:"1",unit:"large"},{name:"Asian pear",quantity:"1",unit:"medium"},{name:"Boiled eggs",quantity:"2",unit:"pieces"},{name:"Kimchi",quantity:"100",unit:"g"},{name:"Soy sauce",quantity:"2",unit:"tbsp"},{name:"Rice vinegar",quantity:"2",unit:"tbsp"},{name:"Korean mustard",quantity:"2",unit:"tsp"},{name:"Ice",quantity:"2",unit:"cups"}], preparation_steps:["Simmer brisket 1 hour until tender. Cool broth completely and skim fat.","Freeze broth until very cold with ice crystals.","Cook noodles in boiling water 2-3 minutes. Rinse under cold water until very cold.","Slice brisket thinly. Julienne cucumber and pear.","Place noodles in bowls. Pour ice-cold broth over.","Top with beef, cucumber, pear, egg and kimchi.","Add ice cubes to keep cold.","Serve with mustard and vinegar on the side."], chef_notes:"The broth must be ice cold — almost frozen. Naengmyeon is the only Korean dish where you want your teeth to hurt from the cold. The chewy noodle texture is characteristic.", serving_suggestions:"Serve in chilled bowls with scissors to cut noodles at the table.", nutrition_estimate:{calories:"385",protein_g:"22",carbohydrates_g:"58",fat_g:"8"}, tags:["Cold Noodles","Pyongyang","Summer","Korean"], img:"https://images.unsplash.com/photo-1569718212165-3a8278d5f624?w=400&q=80" },
  { dish_name:"Hobak Juk (Pumpkin Porridge)", state:"Korea", cuisine:"Korean", category:"Salads", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:30, total_time_minutes:45, servings:4, short_description:"A velvety, golden Korean pumpkin porridge with chewy glutinous rice balls — naturally sweet, nourishing and deeply comforting. Eaten on the winter solstice for good health.", ingredients:[{name:"Kabocha pumpkin",quantity:"600",unit:"g"},{name:"Glutinous rice flour",quantity:"100",unit:"g"},{name:"Water",quantity:"200",unit:"ml"},{name:"Sugar",quantity:"3",unit:"tbsp"},{name:"Salt",quantity:"0.5",unit:"tsp"},{name:"Pine nuts",quantity:"2",unit:"tbsp"}], preparation_steps:["Peel and steam pumpkin until very soft.","Blend pumpkin smooth with water.","Bring blended pumpkin to simmer.","Mix rice flour with water to make small balls.","Drop rice balls into simmering porridge.","Cook until balls float and porridge thickens.","Season with sugar and salt.","Serve topped with pine nuts."], chef_notes:"Kabocha pumpkin creates the richest, most golden hobak juk. The porridge should be thick enough to coat a spoon. Eaten on Dongji (winter solstice) to ward off evil spirits.", serving_suggestions:"Serve warm in bowls as a breakfast or light dessert.", nutrition_estimate:{calories:"185",protein_g:"3",carbohydrates_g:"40",fat_g:"2"}, tags:["Pumpkin","Porridge","Winter Solstice","Healthy"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Injeolmi (Roasted Soybean Rice Cake)", state:"Korea", cuisine:"Korean", category:"Desserts", difficulty_level:"Medium", prep_time_minutes:20, cook_time_minutes:30, total_time_minutes:50, servings:8, short_description:"Korea's most beloved traditional rice cake — pounded glutinous rice coated in fragrant roasted soybean powder. Chewy, nutty and deeply satisfying.", ingredients:[{name:"Glutinous rice",quantity:"400",unit:"g"},{name:"Roasted soybean powder (konggaru)",quantity:"150",unit:"g"},{name:"Sugar",quantity:"3",unit:"tbsp"},{name:"Salt",quantity:"0.5",unit:"tsp"},{name:"Water",quantity:"60",unit:"ml"}], preparation_steps:["Soak glutinous rice 4 hours.","Steam rice 25 minutes until fully cooked.","Transfer hot rice to bowl. Add salt and pound vigorously.","Keep pounding until rice is completely smooth and very stretchy.","Mix soybean powder with sugar on a flat surface.","Coat hands with soybean powder. Pull off pieces of rice cake.","Roll and coat thoroughly in soybean powder.","Cut into pieces and serve."], chef_notes:"Injeolmi must be eaten the same day — it hardens quickly when cold. The pounding is what creates the characteristic stretchy, chewy texture. Pound while very hot.", serving_suggestions:"Serve as a snack or dessert. Also enjoyed with sweet pumpkin or red bean.", nutrition_estimate:{calories:"245",protein_g:"6",carbohydrates_g:"46",fat_g:"4"}, tags:["Rice Cake","Soybean","Traditional","Pounded"], img:"https://images.unsplash.com/photo-1558024920-b41e1887dc32?w=400&q=80" },

];

const vietnameseCuisineData = [
  // ── APPETIZERS ─────────────────────────────────────────────────────────────
  { dish_name:"Goi Cuon (Fresh Spring Rolls)", state:"Vietnam", cuisine:"Vietnamese", category:"Appetizers", difficulty_level:"Easy", prep_time_minutes:30, cook_time_minutes:10, total_time_minutes:40, servings:4, short_description:"Vietnam's iconic fresh spring rolls — rice paper filled with prawns, pork, vermicelli, herbs and lettuce, served with peanut dipping sauce. Fresh, light and utterly delicious.", ingredients:[{name:"Rice paper wrappers",quantity:"16",unit:"pieces"},{name:"Cooked prawns",quantity:"200",unit:"g"},{name:"Pork belly",quantity:"150",unit:"g"},{name:"Rice vermicelli",quantity:"100",unit:"g"},{name:"Lettuce",quantity:"8",unit:"leaves"},{name:"Fresh mint",quantity:"1",unit:"bunch"},{name:"Bean sprouts",quantity:"100",unit:"g"},{name:"Peanut butter",quantity:"4",unit:"tbsp"},{name:"Hoisin sauce",quantity:"3",unit:"tbsp"},{name:"Lime juice",quantity:"2",unit:"tbsp"}], preparation_steps:["Cook pork belly until tender. Cool and slice thinly.","Cook vermicelli, rinse under cold water.","Briefly dip rice paper in warm water until just pliable.","Lay on flat surface. Place lettuce, vermicelli, pork, prawn, mint and sprouts.","Fold sides in and roll tightly.","Make peanut sauce: blend peanut butter, hoisin, lime juice and warm water.","Serve rolls immediately with peanut sauce."], chef_notes:"Rice paper must be dipped briefly — too long and it becomes too soft to roll. Roll firmly but not so tight the filling tears through. Eat immediately or cover with damp cloth.", serving_suggestions:"Serve immediately with peanut dipping sauce and extra herbs on the side.", nutrition_estimate:{calories:"225",protein_g:"14",carbohydrates_g:"28",fat_g:"7"}, tags:["Fresh","Healthy","Spring Rolls","Vietnamese"], img:"https://images.unsplash.com/photo-1582878826629-33b7f57b2a3c?w=400&q=80" },
  { dish_name:"Cha Gio (Fried Spring Rolls)", state:"Vietnam", cuisine:"Vietnamese", category:"Appetizers", difficulty_level:"Medium", prep_time_minutes:40, cook_time_minutes:15, total_time_minutes:55, servings:4, short_description:"Crispy Vietnamese fried spring rolls stuffed with pork, glass noodles, mushrooms and vegetables — golden, crunchy and irresistible with nuoc cham dipping sauce.", ingredients:[{name:"Rice paper wrappers",quantity:"16",unit:"pieces"},{name:"Ground pork",quantity:"300",unit:"g"},{name:"Glass noodles",quantity:"50",unit:"g"},{name:"Wood ear mushrooms",quantity:"30",unit:"g"},{name:"Carrot",quantity:"1",unit:"medium"},{name:"Shallots",quantity:"3",unit:"pieces"},{name:"Fish sauce",quantity:"2",unit:"tbsp"},{name:"Black pepper",quantity:"0.5",unit:"tsp"},{name:"Egg",quantity:"1",unit:"large"},{name:"Oil for frying",quantity:"2",unit:"cups"}], preparation_steps:["Soak noodles and mushrooms. Drain and chop finely.","Mix pork, noodles, mushrooms, carrot, shallots, fish sauce, pepper and egg.","Briefly dip rice paper in water. Place filling near one edge.","Roll tightly, tucking in sides.","Deep fry at 170°C until golden and crispy — about 5 minutes.","Drain on wire rack.","Serve with nuoc cham dipping sauce."], chef_notes:"Vietnamese cha gio uses rice paper, not wheat wrappers — this creates uniquely crispy, bubbly texture. Fry in batches to maintain oil temperature.", serving_suggestions:"Serve wrapped in lettuce leaves with fresh herbs and nuoc cham.", nutrition_estimate:{calories:"285",protein_g:"16",carbohydrates_g:"24",fat_g:"14"}, tags:["Fried","Crispy","Street Food","Vietnamese"], img:"https://images.unsplash.com/photo-1582878826629-33b7f57b2a3c?w=400&q=80" },
  { dish_name:"Banh Xeo (Sizzling Crepes)", state:"Vietnam", cuisine:"Vietnamese", category:"Appetizers", difficulty_level:"Medium", prep_time_minutes:20, cook_time_minutes:20, total_time_minutes:40, servings:4, short_description:"Vietnam's spectacular sizzling crepe — a turmeric-yellow rice flour pancake stuffed with pork, prawns and bean sprouts, eaten wrapped in lettuce with fresh herbs.", ingredients:[{name:"Rice flour",quantity:"200",unit:"g"},{name:"Turmeric powder",quantity:"1",unit:"tsp"},{name:"Coconut milk",quantity:"200",unit:"ml"},{name:"Water",quantity:"150",unit:"ml"},{name:"Pork belly slices",quantity:"200",unit:"g"},{name:"Prawns",quantity:"150",unit:"g"},{name:"Bean sprouts",quantity:"200",unit:"g"},{name:"Spring onion",quantity:"4",unit:"stalks"},{name:"Lettuce",quantity:"1",unit:"head"},{name:"Fresh herbs assorted",quantity:"1",unit:"bunch"}], preparation_steps:["Make batter: mix rice flour, turmeric, coconut milk and water until smooth.","Rest batter 30 minutes.","Cook pork and prawns separately. Season.","Heat pan with oil until very hot — it must sizzle when batter hits.","Pour thin layer of batter, swirl to coat pan.","Add pork, prawns and bean sprouts on one half.","Cover and cook 3 minutes until edges are crispy.","Fold in half and serve immediately."], chef_notes:"The sizzle when batter hits the pan is what gives banh xeo its name. Maximum heat creates the crispy, lacy edges. Thin batter is essential — thick batter makes a doughy crepe.", serving_suggestions:"Tear into pieces and wrap in lettuce with herbs. Dip in nuoc cham.", nutrition_estimate:{calories:"285",protein_g:"16",carbohydrates_g:"30",fat_g:"12"}, tags:["Crepe","Sizzling","Turmeric","Vietnamese"], img:"https://images.unsplash.com/photo-1582878826629-33b7f57b2a3c?w=400&q=80" },
  { dish_name:"Banh Cuon (Steamed Rice Rolls)", state:"Vietnam", cuisine:"Vietnamese", category:"Appetizers", difficulty_level:"Hard", prep_time_minutes:30, cook_time_minutes:30, total_time_minutes:60, servings:4, short_description:"Delicate steamed rice rolls filled with seasoned pork and wood ear mushrooms, drizzled with fried shallots and served with nuoc cham — a beloved Vietnamese breakfast.", ingredients:[{name:"Rice flour",quantity:"200",unit:"g"},{name:"Tapioca flour",quantity:"30",unit:"g"},{name:"Water",quantity:"500",unit:"ml"},{name:"Ground pork",quantity:"200",unit:"g"},{name:"Wood ear mushrooms",quantity:"30",unit:"g"},{name:"Shallots",quantity:"4",unit:"pieces"},{name:"Fish sauce",quantity:"3",unit:"tbsp"},{name:"Black pepper",quantity:"0.5",unit:"tsp"},{name:"Fried shallots",quantity:"3",unit:"tbsp"},{name:"Bean sprouts",quantity:"100",unit:"g"}], preparation_steps:["Mix rice flour and tapioca flour with water into very thin batter.","Soak mushrooms, drain and chop. Cook with pork, fish sauce and pepper.","Steam very thin layer of batter on oiled cloth over boiling water — 1 minute.","Carefully slide cooked sheet off and add filling.","Roll gently into cylinder.","Top with fried shallots and serve with nuoc cham and bean sprouts."], chef_notes:"Banh cuon requires a special steaming cloth technique. The rice sheet must be paper-thin and cooked in seconds. This is one of Vietnam's most technically demanding dishes.", serving_suggestions:"Serve immediately topped with fried shallots and crispy cha lua pork sausage.", nutrition_estimate:{calories:"245",protein_g:"12",carbohydrates_g:"36",fat_g:"7"}, tags:["Steamed","Delicate","Breakfast","Vietnamese"], img:"https://images.unsplash.com/photo-1582878826629-33b7f57b2a3c?w=400&q=80" },
  { dish_name:"Nem Nuong (Grilled Pork Skewers)", state:"Vietnam", cuisine:"Vietnamese", category:"Appetizers", difficulty_level:"Medium", prep_time_minutes:30, cook_time_minutes:15, total_time_minutes:45, servings:4, short_description:"Fragrant grilled pork patties on skewers with lemongrass and garlic — eaten wrapped in rice paper with fresh herbs. A beloved central Vietnamese street food.", ingredients:[{name:"Ground pork",quantity:"400",unit:"g"},{name:"Lemongrass",quantity:"2",unit:"stalks"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Shallots",quantity:"3",unit:"pieces"},{name:"Fish sauce",quantity:"2",unit:"tbsp"},{name:"Sugar",quantity:"1",unit:"tbsp"},{name:"Baking powder",quantity:"0.5",unit:"tsp"},{name:"Rice paper",quantity:"12",unit:"pieces"},{name:"Fresh herbs",quantity:"1",unit:"bunch"},{name:"Bamboo skewers",quantity:"12",unit:"pieces"}], preparation_steps:["Finely mince lemongrass, garlic and shallots.","Mix with pork, fish sauce, sugar and baking powder.","Knead until sticky. Refrigerate 30 minutes.","Mould around skewers into elongated patties.","Grill over charcoal or high heat 4 minutes per side.","Brush with oil while grilling.","Serve with rice paper, fresh herbs and dipping sauce."], chef_notes:"Baking powder makes the pork patties slightly bouncy and helps them stay juicy. Lemongrass must be very finely minced to avoid stringy texture.", serving_suggestions:"Wrap in rice paper with herbs and rice vermicelli. Dip in nuoc cham.", nutrition_estimate:{calories:"265",protein_g:"22",carbohydrates_g:"14",fat_g:"14"}, tags:["Grilled","Pork","Lemongrass","Central Vietnam"], img:"https://images.unsplash.com/photo-1582878826629-33b7f57b2a3c?w=400&q=80" },
  { dish_name:"Banh Mi (Vietnamese Sandwich)", state:"Vietnam", cuisine:"Vietnamese", category:"Appetizers", difficulty_level:"Easy", prep_time_minutes:20, cook_time_minutes:10, total_time_minutes:30, servings:4, short_description:"The world's greatest sandwich — a crispy French baguette filled with pate, Vietnamese cold cuts, pickled vegetables, fresh coriander and chilli. A perfect fusion of French and Vietnamese.", ingredients:[{name:"Vietnamese baguette",quantity:"4",unit:"pieces"},{name:"Pork pate",quantity:"100",unit:"g"},{name:"Cha lua (pork sausage)",quantity:"200",unit:"g"},{name:"Daikon radish",quantity:"150",unit:"g"},{name:"Carrot",quantity:"1",unit:"medium"},{name:"Rice vinegar",quantity:"3",unit:"tbsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Cucumber",quantity:"1",unit:"medium"},{name:"Fresh coriander",quantity:"1",unit:"bunch"},{name:"Bird's eye chilli",quantity:"4",unit:"pieces"},{name:"Mayonnaise",quantity:"4",unit:"tbsp"}], preparation_steps:["Quick-pickle daikon and carrot: julienne and soak in vinegar and sugar 30 minutes.","Warm baguette until exterior is crispy.","Spread pate on one side, mayonnaise on other.","Layer with cha lua slices.","Add pickled vegetables, cucumber slices.","Top with coriander and sliced chilli.","Press together and serve immediately."], chef_notes:"The Vietnamese baguette is lighter and crispier than French bread — the airy crumb holds the fillings without becoming soggy. The contrast of pate richness with pickled vegetables is the genius.", serving_suggestions:"Eat immediately while bread is crispy. Wrap in paper as a street food.", nutrition_estimate:{calories:"385",protein_g:"18",carbohydrates_g:"48",fat_g:"14"}, tags:["Sandwich","French-Vietnamese","Street Food","Fusion"], img:"https://images.unsplash.com/photo-1582878826629-33b7f57b2a3c?w=400&q=80" },
  { dish_name:"Bun Cha (Grilled Pork with Noodles)", state:"Vietnam", cuisine:"Vietnamese", category:"Appetizers", difficulty_level:"Medium", prep_time_minutes:30, cook_time_minutes:20, total_time_minutes:50, servings:4, short_description:"Hanoi's most iconic dish — grilled pork patties and belly in a sweet-sour nuoc cham broth, served alongside rice noodles and a mountain of fresh herbs.", ingredients:[{name:"Pork belly",quantity:"300",unit:"g"},{name:"Ground pork",quantity:"200",unit:"g"},{name:"Rice vermicelli",quantity:"200",unit:"g"},{name:"Fish sauce",quantity:"4",unit:"tbsp"},{name:"Sugar",quantity:"3",unit:"tbsp"},{name:"Lime juice",quantity:"3",unit:"tbsp"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Bird's eye chilli",quantity:"3",unit:"pieces"},{name:"Shallots",quantity:"3",unit:"pieces"},{name:"Fresh herbs assorted",quantity:"1",unit:"bunch"}], preparation_steps:["Slice pork belly thinly. Marinate with fish sauce, sugar and shallots.","Form ground pork into small patties with fish sauce.","Grill both over charcoal until charred and fragrant.","Make dipping broth: diluted fish sauce with sugar, lime, garlic and chilli.","Place grilled pork in individual bowls of broth.","Cook vermicelli. Rinse and serve alongside.","Serve with giant platter of fresh herbs."], chef_notes:"Charcoal grilling is essential for authentic bun cha — the smoky char is the defining flavour. Dip the noodles and herbs into the broth with each bite.", serving_suggestions:"Serve pork in broth bowls alongside noodles and herbs. Dip noodles into broth.", nutrition_estimate:{calories:"385",protein_g:"28",carbohydrates_g:"38",fat_g:"14"}, tags:["Hanoi","Grilled Pork","Noodles","Famous"], img:"https://images.unsplash.com/photo-1582878826629-33b7f57b2a3c?w=400&q=80" },
  { dish_name:"Banh Khot (Mini Coconut Pancakes)", state:"Vietnam", cuisine:"Vietnamese", category:"Appetizers", difficulty_level:"Medium", prep_time_minutes:20, cook_time_minutes:20, total_time_minutes:40, servings:4, short_description:"Tiny, crispy-based coconut rice pancakes topped with a whole prawn — a southern Vietnamese speciality served with fresh lettuce and herbs.", ingredients:[{name:"Rice flour",quantity:"150",unit:"g"},{name:"Coconut milk",quantity:"200",unit:"ml"},{name:"Turmeric",quantity:"0.5",unit:"tsp"},{name:"Spring onion",quantity:"3",unit:"stalks"},{name:"Whole prawns",quantity:"16",unit:"small"},{name:"Mung bean",quantity:"50",unit:"g"},{name:"Fish sauce",quantity:"2",unit:"tbsp"},{name:"Lettuce",quantity:"1",unit:"head"},{name:"Fresh herbs",quantity:"1",unit:"bunch"},{name:"Oil",quantity:"3",unit:"tbsp"}], preparation_steps:["Mix rice flour, coconut milk, turmeric and spring onion into batter.","Soak and cook mung beans until soft.","Heat special banh khot pan or mini muffin pan.","Oil each cavity. Pour batter to fill halfway.","Place one prawn and some mung bean on top.","Cover and cook 4-5 minutes until base is crispy.","Remove and serve with lettuce and herbs."], chef_notes:"The base must be genuinely crispy — this requires good heat and adequate oil. The contrast of crispy base and soft coconut centre is what makes banh khot special.", serving_suggestions:"Wrap in lettuce with herbs. Dip in nuoc cham.", nutrition_estimate:{calories:"205",protein_g:"10",carbohydrates_g:"28",fat_g:"7"}, tags:["Coconut Pancake","Southern Vietnam","Prawn","Mini"], img:"https://images.unsplash.com/photo-1582878826629-33b7f57b2a3c?w=400&q=80" },
  { dish_name:"Com Chien (Vietnamese Fried Rice)", state:"Vietnam", cuisine:"Vietnamese", category:"Appetizers", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:15, total_time_minutes:25, servings:4, short_description:"Vietnamese fried rice with egg, vegetables and soy sauce — lighter and simpler than Chinese fried rice, with a distinctly Vietnamese character from fish sauce.", ingredients:[{name:"Cold cooked jasmine rice",quantity:"600",unit:"g"},{name:"Eggs",quantity:"3",unit:"large"},{name:"Spring onion",quantity:"4",unit:"stalks"},{name:"Garlic",quantity:"3",unit:"cloves"},{name:"Fish sauce",quantity:"2",unit:"tbsp"},{name:"Soy sauce",quantity:"1",unit:"tbsp"},{name:"White pepper",quantity:"0.5",unit:"tsp"},{name:"Oil",quantity:"3",unit:"tbsp"},{name:"Lime",quantity:"2",unit:"pieces"},{name:"Cucumber",quantity:"1",unit:"medium"}], preparation_steps:["Heat wok until smoking. Add oil.","Fry garlic briefly. Add cold rice.","Stir-fry vigorously on high heat.","Push rice aside. Scramble eggs in pan.","Mix eggs with rice.","Season with fish sauce, soy and white pepper.","Add spring onion and toss.","Serve with lime, cucumber and extra fish sauce."], chef_notes:"Fish sauce instead of salt is what gives Vietnamese fried rice its distinctive umami character. Day-old rice is essential. Serve with a squeeze of lime.", serving_suggestions:"Serve with cucumber slices, lime and fried egg on top.", nutrition_estimate:{calories:"345",protein_g:"12",carbohydrates_g:"56",fat_g:"9"}, tags:["Fried Rice","Quick","Everyday","Vietnamese"], img:"https://images.unsplash.com/photo-1582878826629-33b7f57b2a3c?w=400&q=80" },
  { dish_name:"Nuoc Cham (Vietnamese Dipping Sauce)", state:"Vietnam", cuisine:"Vietnamese", category:"Appetizers", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:0, total_time_minutes:10, servings:8, short_description:"Vietnam's essential dipping sauce — a perfectly balanced blend of fish sauce, lime juice, sugar, garlic and chilli. The soul of Vietnamese cuisine in a small bowl.", ingredients:[{name:"Fish sauce",quantity:"4",unit:"tbsp"},{name:"Lime juice",quantity:"4",unit:"tbsp"},{name:"Sugar",quantity:"3",unit:"tbsp"},{name:"Water",quantity:"4",unit:"tbsp"},{name:"Garlic",quantity:"3",unit:"cloves"},{name:"Bird's eye chilli",quantity:"2",unit:"pieces"},{name:"Carrot",quantity:"0.25",unit:"medium"}], preparation_steps:["Dissolve sugar in warm water completely.","Add fish sauce and lime juice.","Taste — should be equally salty, sour and sweet.","Mince garlic finely. Slice chilli into rounds.","Add garlic and chilli to sauce.","Julienne carrot into tiny strips and add.","Let rest 10 minutes for flavours to meld.","Adjust balance to taste."], chef_notes:"Nuoc cham must be perfectly balanced — no single flavour should dominate. Taste constantly and adjust. Fresh lime juice is essential — bottled lime juice ruins it.", serving_suggestions:"Serve alongside virtually every Vietnamese dish as a dipping sauce.", nutrition_estimate:{calories:"35",protein_g:"1",carbohydrates_g:"8",fat_g:"0"}, tags:["Dipping Sauce","Essential","Vietnamese","Condiment"], img:"https://images.unsplash.com/photo-1582878826629-33b7f57b2a3c?w=400&q=80" },

  // ── SOUPS ───────────────────────────────────────────────────────────────────
  { dish_name:"Pho Bo (Beef Noodle Soup)", state:"Vietnam", cuisine:"Vietnamese", category:"Soups", difficulty_level:"Hard", prep_time_minutes:30, cook_time_minutes:360, total_time_minutes:390, servings:6, short_description:"Vietnam's most iconic dish — a crystal clear, deeply aromatic beef broth simmered for 6+ hours with charred ginger and spices, served with rice noodles and paper-thin beef.", ingredients:[{name:"Beef marrow bones",quantity:"1.5",unit:"kg"},{name:"Beef brisket",quantity:"500",unit:"g"},{name:"Ginger",quantity:"100",unit:"g"},{name:"Onion",quantity:"2",unit:"large"},{name:"Star anise",quantity:"6",unit:"pieces"},{name:"Cinnamon sticks",quantity:"2",unit:"pieces"},{name:"Cloves",quantity:"5",unit:"pieces"},{name:"Fish sauce",quantity:"4",unit:"tbsp"},{name:"Rock sugar",quantity:"30",unit:"g"},{name:"Pho noodles",quantity:"400",unit:"g"},{name:"Beef sirloin",quantity:"300",unit:"g"},{name:"Bean sprouts",quantity:"200",unit:"g"},{name:"Fresh basil",quantity:"1",unit:"bunch"},{name:"Lime",quantity:"4",unit:"pieces"}], preparation_steps:["Char ginger and onion directly over flame until blackened outside.","Blanch bones in boiling water 10 minutes. Rinse thoroughly.","Dry-toast spices until fragrant.","Simmer bones with charred aromatics and spices 5-6 hours.","Add brisket in last 2 hours.","Strain broth. Season with fish sauce and rock sugar.","Cook noodles. Slice brisket thinly. Slice raw sirloin paper-thin.","Fill bowls with noodles. Ladle boiling broth over raw beef — it cooks instantly.","Serve with sprouts, basil, lime and chilli."], chef_notes:"Charring the ginger and onion is non-negotiable — it creates the distinctive smoky-sweet depth of pho. Skim constantly during simmering for a clear broth. Never rush pho.", serving_suggestions:"Serve with a platter of sprouts, basil, lime, chilli and hoisin sauce.", nutrition_estimate:{calories:"385",protein_g:"32",carbohydrates_g:"42",fat_g:"10"}, tags:["Pho","National Dish","6-Hour Broth","Iconic"], img:"https://images.unsplash.com/photo-1582878826629-33b7f57b2a3c?w=400&q=80" },
  { dish_name:"Pho Ga (Chicken Noodle Soup)", state:"Vietnam", cuisine:"Vietnamese", category:"Soups", difficulty_level:"Medium", prep_time_minutes:20, cook_time_minutes:120, total_time_minutes:140, servings:4, short_description:"The lighter, equally aromatic chicken version of Vietnam's national soup — a golden, crystal-clear chicken broth with the same warming spices as pho bo.", ingredients:[{name:"Whole chicken",quantity:"1.5",unit:"kg"},{name:"Ginger",quantity:"60",unit:"g"},{name:"Onion",quantity:"1",unit:"large"},{name:"Star anise",quantity:"4",unit:"pieces"},{name:"Cinnamon stick",quantity:"1",unit:"piece"},{name:"Fish sauce",quantity:"3",unit:"tbsp"},{name:"Rock sugar",quantity:"20",unit:"g"},{name:"Pho noodles",quantity:"300",unit:"g"},{name:"Spring onion",quantity:"4",unit:"stalks"},{name:"Coriander",quantity:"1",unit:"bunch"},{name:"Bean sprouts",quantity:"150",unit:"g"}], preparation_steps:["Char ginger and onion over flame.","Blanch chicken briefly. Rinse.","Simmer chicken with charred aromatics and spices 1.5 hours.","Remove chicken. Shred meat from bones.","Strain broth and season with fish sauce and rock sugar.","Cook noodles. Place in bowls with shredded chicken.","Ladle hot broth over.","Top with spring onion, coriander and bean sprouts."], chef_notes:"Pho ga broth should be golden and clear — not cloudy. The chicken fat gives it a silkier texture than beef pho. Remove the chicken when just cooked to keep it tender.", serving_suggestions:"Serve with lime, chilli, basil and hoisin like beef pho.", nutrition_estimate:{calories:"325",protein_g:"28",carbohydrates_g:"38",fat_g:"8"}, tags:["Pho","Chicken","Lighter","Vietnamese"], img:"https://images.unsplash.com/photo-1582878826629-33b7f57b2a3c?w=400&q=80" },
  { dish_name:"Bun Bo Hue (Spicy Beef Noodle Soup)", state:"Vietnam", cuisine:"Vietnamese", category:"Soups", difficulty_level:"Hard", prep_time_minutes:30, cook_time_minutes:180, total_time_minutes:210, servings:4, short_description:"Central Vietnam's bold, spicy answer to pho — a lemongrass-scented beef broth with shrimp paste and chilli, served with thick round noodles and tender beef shank.", ingredients:[{name:"Beef shank",quantity:"600",unit:"g"},{name:"Pork trotters",quantity:"2",unit:"pieces"},{name:"Lemongrass",quantity:"4",unit:"stalks"},{name:"Shrimp paste (mam ruoc)",quantity:"2",unit:"tbsp"},{name:"Chilli oil",quantity:"2",unit:"tbsp"},{name:"Fish sauce",quantity:"4",unit:"tbsp"},{name:"Sugar",quantity:"1",unit:"tbsp"},{name:"Bun bo hue noodles",quantity:"400",unit:"g"},{name:"Spring onion",quantity:"4",unit:"stalks"},{name:"Banana blossom",quantity:"200",unit:"g"},{name:"Bean sprouts",quantity:"150",unit:"g"}], preparation_steps:["Simmer beef shank and pork trotters 2.5 hours.","Bruise lemongrass and add in final hour.","Mix shrimp paste with warm water and add to broth.","Season with fish sauce, sugar and chilli oil.","Cook noodles separately.","Slice beef shank thinly.","Fill bowls with noodles and beef.","Ladle spicy broth over. Top with spring onion."], chef_notes:"Shrimp paste (mam ruoc) is the defining ingredient of bun bo hue — its pungent fermented flavour is irreplaceable. The broth should be spicy, savoury and deeply lemongrass-scented.", serving_suggestions:"Serve with shredded banana blossom, bean sprouts, lime and fresh herbs.", nutrition_estimate:{calories:"425",protein_g:"32",carbohydrates_g:"44",fat_g:"14"}, tags:["Hue","Spicy","Lemongrass","Central Vietnam"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Canh Chua (Sweet and Sour Soup)", state:"Vietnam", cuisine:"Vietnamese", category:"Soups", difficulty_level:"Easy", prep_time_minutes:20, cook_time_minutes:20, total_time_minutes:40, servings:4, short_description:"Southern Vietnam's beloved sweet and sour fish soup with pineapple, tomatoes and tamarind — a beautiful balance of sour, sweet and savoury that sings with freshness.", ingredients:[{name:"Catfish or white fish",quantity:"400",unit:"g"},{name:"Pineapple",quantity:"200",unit:"g"},{name:"Tomatoes",quantity:"2",unit:"large"},{name:"Bean sprouts",quantity:"150",unit:"g"},{name:"Taro stem",quantity:"100",unit:"g"},{name:"Tamarind paste",quantity:"3",unit:"tbsp"},{name:"Fish sauce",quantity:"3",unit:"tbsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Okra",quantity:"6",unit:"pieces"},{name:"Fresh herbs",quantity:"1",unit:"bunch"}], preparation_steps:["Bring water to boil. Add tamarind paste, fish sauce and sugar.","Add pineapple chunks and tomatoes.","Add taro stem and okra.","Gently add fish pieces — cook 5 minutes only.","Add bean sprouts at the very end.","Adjust sour-sweet-salty balance.","Top with fried garlic oil.","Garnish with rice paddy herbs and sawtooth coriander."], chef_notes:"The balance of tamarind sour, pineapple sweet and fish sauce salt must be perfect. Add bean sprouts at the end — they should remain crunchy. Never overcook the fish.", serving_suggestions:"Serve with rice as part of a Vietnamese family meal.", nutrition_estimate:{calories:"185",protein_g:"22",carbohydrates_g:"16",fat_g:"4"}, tags:["Sweet and Sour","Southern Vietnam","Fish","Tamarind"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Mien Ga (Glass Noodle Chicken Soup)", state:"Vietnam", cuisine:"Vietnamese", category:"Soups", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:60, total_time_minutes:75, servings:4, short_description:"A light, nourishing Vietnamese chicken soup with glass noodles, mushrooms and ginger — simple, delicate and deeply comforting.", ingredients:[{name:"Whole chicken",quantity:"1",unit:"kg"},{name:"Glass noodles",quantity:"150",unit:"g"},{name:"Wood ear mushrooms",quantity:"30",unit:"g"},{name:"Ginger",quantity:"30",unit:"g"},{name:"Spring onion",quantity:"4",unit:"stalks"},{name:"Fish sauce",quantity:"3",unit:"tbsp"},{name:"Salt",quantity:"0.5",unit:"tsp"},{name:"White pepper",quantity:"0.5",unit:"tsp"},{name:"Fried shallots",quantity:"3",unit:"tbsp"}], preparation_steps:["Simmer chicken with ginger 45 minutes until tender.","Remove chicken, shred meat and discard skin.","Soak glass noodles and mushrooms. Drain.","Add mushrooms to broth. Simmer 5 minutes.","Season with fish sauce and salt.","Add glass noodles and cook 2 minutes.","Add shredded chicken.","Serve topped with spring onion, fried shallots and white pepper."], chef_notes:"Glass noodles absorb broth quickly — add them last and serve immediately. Fried shallots are essential for the authentic Vietnamese flavour.", serving_suggestions:"Serve in deep bowls topped with fried shallots and white pepper.", nutrition_estimate:{calories:"285",protein_g:"24",carbohydrates_g:"28",fat_g:"8"}, tags:["Glass Noodles","Chicken","Comforting","Vietnamese"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Sup Mang Cua (Crab and Asparagus Soup)", state:"Vietnam", cuisine:"Vietnamese", category:"Soups", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:20, total_time_minutes:35, servings:4, short_description:"Vietnam's elegant banquet soup — a silky, golden crab and asparagus soup thickened with egg whites. A French-Vietnamese fusion beloved at celebrations.", ingredients:[{name:"Crab meat",quantity:"300",unit:"g"},{name:"Canned asparagus",quantity:"400",unit:"g"},{name:"Chicken stock",quantity:"800",unit:"ml"},{name:"Egg whites",quantity:"3",unit:"large"},{name:"Tapioca starch",quantity:"2",unit:"tbsp"},{name:"Fish sauce",quantity:"2",unit:"tbsp"},{name:"Salt",quantity:"0.5",unit:"tsp"},{name:"White pepper",quantity:"0.5",unit:"tsp"},{name:"Spring onion",quantity:"3",unit:"stalks"},{name:"Coriander",quantity:"4",unit:"sprigs"}], preparation_steps:["Bring stock to boil.","Add asparagus pieces and crab meat.","Mix tapioca starch with cold water.","Slowly pour starch mixture into simmering soup while stirring.","Beat egg whites until frothy. Pour in thin stream while stirring.","Season with fish sauce, salt and pepper.","Serve topped with spring onion and coriander."], chef_notes:"The egg white creates the characteristic silky, slightly gelatinous texture. Pour it in a thin stream while stirring constantly for delicate wisps throughout.", serving_suggestions:"Serve as an elegant starter at Vietnamese celebrations and banquets.", nutrition_estimate:{calories:"145",protein_g:"18",carbohydrates_g:"10",fat_g:"3"}, tags:["Crab","Asparagus","Banquet","Elegant"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Chao Ga (Vietnamese Rice Porridge)", state:"Vietnam", cuisine:"Vietnamese", category:"Soups", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:60, total_time_minutes:70, servings:4, short_description:"Vietnam's healing rice porridge — soft rice simmered with chicken in a fragrant broth topped with ginger, spring onion and crispy shallots. The Vietnamese answer to congee.", ingredients:[{name:"Jasmine rice",quantity:"150",unit:"g"},{name:"Chicken pieces",quantity:"400",unit:"g"},{name:"Ginger",quantity:"30",unit:"g"},{name:"Spring onion",quantity:"4",unit:"stalks"},{name:"Fish sauce",quantity:"2",unit:"tbsp"},{name:"Salt",quantity:"0.5",unit:"tsp"},{name:"White pepper",quantity:"1",unit:"tsp"},{name:"Fried shallots",quantity:"3",unit:"tbsp"},{name:"Lime",quantity:"2",unit:"pieces"},{name:"Fresh coriander",quantity:"1",unit:"bunch"}], preparation_steps:["Simmer chicken with ginger until tender. Remove and shred.","Add rice to broth.","Cook on low heat 45 minutes until rice is completely soft.","Stir regularly — porridge should be silky, not gluey.","Return chicken to porridge.","Season with fish sauce and salt.","Serve topped with ginger strips, spring onion, fried shallots and coriander.","Squeeze lime and add white pepper."], chef_notes:"Chao should be silky smooth with a flowing consistency. Keep stirring as the rice cooks — it sticks to the bottom. Toppings are essential, not optional.", serving_suggestions:"Serve as a healing breakfast or light meal. Essential when sick.", nutrition_estimate:{calories:"265",protein_g:"18",carbohydrates_g:"38",fat_g:"5"}, tags:["Rice Porridge","Healing","Breakfast","Vietnamese"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Lau (Vietnamese Hot Pot)", state:"Vietnam", cuisine:"Vietnamese", category:"Soups", difficulty_level:"Medium", prep_time_minutes:30, cook_time_minutes:30, total_time_minutes:60, servings:4, short_description:"Vietnam's communal hot pot — a fragrant lemongrass and coconut milk broth at the table with seafood, meat and vegetables cooked communally. A festive Vietnamese tradition.", ingredients:[{name:"Lemongrass",quantity:"4",unit:"stalks"},{name:"Coconut milk",quantity:"200",unit:"ml"},{name:"Chicken stock",quantity:"1",unit:"litre"},{name:"Mixed seafood",quantity:"400",unit:"g"},{name:"Pork or beef slices",quantity:"300",unit:"g"},{name:"Tofu",quantity:"200",unit:"g"},{name:"Vegetables assorted",quantity:"400",unit:"g"},{name:"Rice noodles",quantity:"300",unit:"g"},{name:"Turmeric",quantity:"1",unit:"tsp"},{name:"Fish sauce",quantity:"3",unit:"tbsp"}], preparation_steps:["Make broth: simmer lemongrass in stock 20 minutes.","Add coconut milk and turmeric.","Season with fish sauce.","Set up portable burner at table.","Arrange all raw ingredients on platters around pot.","Bring broth to simmer at table.","Cook ingredients individually in broth.","Serve with dipping sauces and herbs."], chef_notes:"Vietnamese lau differs from Chinese hot pot in its use of lemongrass and coconut milk. The broth becomes increasingly flavourful as cooking progresses.", serving_suggestions:"Set up at the table communally. Serve with rice noodles, herbs and dipping sauces.", nutrition_estimate:{calories:"345",protein_g:"28",carbohydrates_g:"24",fat_g:"14"}, tags:["Hot Pot","Communal","Festive","Vietnamese"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Bun Rieu (Tomato Crab Noodle Soup)", state:"Vietnam", cuisine:"Vietnamese", category:"Soups", difficulty_level:"Hard", prep_time_minutes:30, cook_time_minutes:60, total_time_minutes:90, servings:4, short_description:"A uniquely Vietnamese tomato-based crab noodle soup with fluffy crab and tofu dumplings floating in a tangy tomato broth — deeply flavourful and unlike any other soup.", ingredients:[{name:"River crab or crab paste",quantity:"300",unit:"g"},{name:"Tomatoes",quantity:"4",unit:"large"},{name:"Firm tofu",quantity:"200",unit:"g"},{name:"Pork ribs",quantity:"300",unit:"g"},{name:"Shrimp paste",quantity:"1",unit:"tbsp"},{name:"Rice vermicelli",quantity:"300",unit:"g"},{name:"Tamarind",quantity:"2",unit:"tbsp"},{name:"Fish sauce",quantity:"3",unit:"tbsp"},{name:"Spring onion",quantity:"4",unit:"stalks"},{name:"Fried tofu",quantity:"150",unit:"g"}], preparation_steps:["Simmer pork ribs to make broth.","Blend crab with water and strain. Reserve solid crab paste.","Heat crab liquid gently — curd-like crab cake forms on surface.","Fry tomatoes in oil until soft. Add to broth.","Add tamarind and fish sauce.","Carefully ladle crab cake into broth.","Add fried tofu.","Serve over vermicelli topped with spring onion and herbs."], chef_notes:"The floating crab dumplings form naturally when crab liquid is heated — they must be scooped gently to keep them intact. Bun rieu is one of Vietnam's most complex soups.", serving_suggestions:"Serve with banana blossom, bean sprouts, lime and shrimp paste.", nutrition_estimate:{calories:"345",protein_g:"24",carbohydrates_g:"40",fat_g:"10"}, tags:["Crab","Tomato","Complex","Vietnamese"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },
  { dish_name:"Banh Canh (Thick Noodle Soup)", state:"Vietnam", cuisine:"Vietnamese", category:"Soups", difficulty_level:"Medium", prep_time_minutes:20, cook_time_minutes:60, total_time_minutes:80, servings:4, short_description:"A comforting Vietnamese soup with thick, chewy tapioca noodles in a clear pork broth — the Vietnamese equivalent of udon in its satisfying heartiness.", ingredients:[{name:"Pork bones",quantity:"600",unit:"g"},{name:"Banh canh noodles (thick tapioca)",quantity:"400",unit:"g"},{name:"Pork leg",quantity:"300",unit:"g"},{name:"Fish sauce",quantity:"3",unit:"tbsp"},{name:"Shallots",quantity:"4",unit:"pieces"},{name:"Ginger",quantity:"20",unit:"g"},{name:"Spring onion",quantity:"4",unit:"stalks"},{name:"Fried shallots",quantity:"3",unit:"tbsp"},{name:"White pepper",quantity:"1",unit:"tsp"}], preparation_steps:["Blanch pork bones. Cover with fresh water and simmer 1 hour.","Add charred shallots and ginger.","Add pork leg. Cook 30 minutes.","Remove pork leg, slice thinly.","Season broth with fish sauce and salt.","Cook thick noodles separately until tender.","Place noodles in bowls with pork slices.","Ladle hot broth over. Top with fried shallots and pepper."], chef_notes:"Banh canh noodles are much thicker and chewier than other Vietnamese noodles — their texture is the star of this dish. Do not overcook or they become mushy.", serving_suggestions:"Serve with lime, chilli and extra fish sauce on the side.", nutrition_estimate:{calories:"365",protein_g:"22",carbohydrates_g:"52",fat_g:"8"}, tags:["Thick Noodles","Comfort","Vietnamese","Hearty"], img:"https://images.unsplash.com/photo-1547592166-23ac45744acd?w=400&q=80" },

  // ── SALADS ──────────────────────────────────────────────────────────────────
  { dish_name:"Goi Ga (Vietnamese Chicken Salad)", state:"Vietnam", cuisine:"Vietnamese", category:"Salads", difficulty_level:"Easy", prep_time_minutes:25, cook_time_minutes:10, total_time_minutes:35, servings:4, short_description:"A refreshing Vietnamese salad of poached chicken with cabbage, mint, fried shallots and a tangy lime dressing — light, fragrant and utterly satisfying.", ingredients:[{name:"Chicken breast",quantity:"400",unit:"g"},{name:"Cabbage",quantity:"300",unit:"g"},{name:"Carrot",quantity:"1",unit:"large"},{name:"Fresh mint",quantity:"1",unit:"bunch"},{name:"Vietnamese coriander",quantity:"1",unit:"bunch"},{name:"Fried shallots",quantity:"4",unit:"tbsp"},{name:"Roasted peanuts",quantity:"4",unit:"tbsp"},{name:"Lime juice",quantity:"4",unit:"tbsp"},{name:"Fish sauce",quantity:"3",unit:"tbsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Chilli",quantity:"2",unit:"pieces"}], preparation_steps:["Poach chicken breast until just cooked. Cool and shred finely by hand.","Shred cabbage very finely. Julienne carrot.","Make dressing: lime juice, fish sauce, sugar and chilli.","Combine chicken, cabbage and carrot.","Pour dressing and toss well.","Add mint and Vietnamese coriander.","Top with fried shallots and peanuts.","Serve immediately."], chef_notes:"Hand-shredding chicken creates better texture for salads than knife-cutting. Vietnamese coriander (rau ram) has a unique lemony pepper flavour essential for authentic goi ga.", serving_suggestions:"Serve immediately as a starter or light meal.", nutrition_estimate:{calories:"245",protein_g:"26",carbohydrates_g:"16",fat_g:"8"}, tags:["Chicken Salad","Refreshing","Herbs","Vietnamese"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Goi Du Du (Green Papaya Salad)", state:"Vietnam", cuisine:"Vietnamese", category:"Salads", difficulty_level:"Easy", prep_time_minutes:20, cook_time_minutes:10, total_time_minutes:30, servings:4, short_description:"Vietnam's version of green papaya salad — shredded unripe papaya with beef jerky, basil and a tangy lime dressing. Lighter and more herbaceous than the Thai version.", ingredients:[{name:"Green papaya",quantity:"400",unit:"g"},{name:"Beef jerky (kho bo)",quantity:"100",unit:"g"},{name:"Carrot",quantity:"1",unit:"medium"},{name:"Fresh basil",quantity:"1",unit:"bunch"},{name:"Roasted peanuts",quantity:"4",unit:"tbsp"},{name:"Lime juice",quantity:"4",unit:"tbsp"},{name:"Fish sauce",quantity:"3",unit:"tbsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Garlic",quantity:"2",unit:"cloves"},{name:"Bird's eye chilli",quantity:"2",unit:"pieces"}], preparation_steps:["Peel and shred papaya into thin strips.","Julienne carrot.","Shred beef jerky into strips.","Make dressing: lime juice, fish sauce, sugar, garlic and chilli.","Toss papaya and carrot with dressing.","Add beef jerky and basil.","Top with peanuts.","Serve immediately."], chef_notes:"Vietnamese green papaya salad uses beef jerky instead of dried shrimp, giving it a meatier, different flavour than Thai som tam. The papaya should be firm and unripe.", serving_suggestions:"Serve immediately as a starter. Best eaten fresh before papaya wilts.", nutrition_estimate:{calories:"185",protein_g:"10",carbohydrates_g:"22",fat_g:"7"}, tags:["Green Papaya","Beef Jerky","Refreshing","Vietnamese"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Goi Tom (Prawn Salad)", state:"Vietnam", cuisine:"Vietnamese", category:"Salads", difficulty_level:"Easy", prep_time_minutes:20, cook_time_minutes:5, total_time_minutes:25, servings:4, short_description:"A vibrant Vietnamese prawn salad with fresh herbs, pineapple and crispy shallots in a tangy lime dressing — tropical, fresh and deeply satisfying.", ingredients:[{name:"Cooked prawns",quantity:"300",unit:"g"},{name:"Pineapple",quantity:"150",unit:"g"},{name:"Cucumber",quantity:"1",unit:"large"},{name:"Shallots",quantity:"4",unit:"pieces"},{name:"Fresh mint",quantity:"1",unit:"bunch"},{name:"Coriander",quantity:"1",unit:"bunch"},{name:"Fried shallots",quantity:"3",unit:"tbsp"},{name:"Roasted peanuts",quantity:"3",unit:"tbsp"},{name:"Lime juice",quantity:"4",unit:"tbsp"},{name:"Fish sauce",quantity:"2",unit:"tbsp"},{name:"Sugar",quantity:"1",unit:"tbsp"}], preparation_steps:["Peel and devein prawns. Halve lengthwise.","Dice pineapple. Slice cucumber thinly.","Slice shallots thinly.","Make dressing: lime juice, fish sauce and sugar.","Combine prawns, pineapple, cucumber and shallots.","Add dressing and toss.","Add fresh herbs and toss gently.","Top with fried shallots and peanuts."], chef_notes:"Pineapple adds natural sweetness and acidity that complements prawns beautifully. Use fresh pineapple only — canned pineapple is too sweet and soft.", serving_suggestions:"Serve as a refreshing starter or light lunch.", nutrition_estimate:{calories:"185",protein_g:"18",carbohydrates_g:"18",fat_g:"5"}, tags:["Prawn","Pineapple","Tropical","Vietnamese"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Goi Cuon Chay (Vegetarian Spring Roll Salad)", state:"Vietnam", cuisine:"Vietnamese", category:"Salads", difficulty_level:"Easy", prep_time_minutes:25, cook_time_minutes:0, total_time_minutes:25, servings:4, short_description:"A deconstructed version of Vietnamese fresh spring rolls as a salad — all the fresh ingredients without the wrapping, dressed with a tangy herb dressing.", ingredients:[{name:"Rice vermicelli",quantity:"150",unit:"g"},{name:"Lettuce",quantity:"200",unit:"g"},{name:"Cucumber",quantity:"1",unit:"large"},{name:"Carrot",quantity:"1",unit:"medium"},{name:"Fresh mint",quantity:"1",unit:"bunch"},{name:"Bean sprouts",quantity:"150",unit:"g"},{name:"Tofu",quantity:"200",unit:"g"},{name:"Lime juice",quantity:"4",unit:"tbsp"},{name:"Soy sauce",quantity:"2",unit:"tbsp"},{name:"Sugar",quantity:"1",unit:"tbsp"},{name:"Roasted peanuts",quantity:"4",unit:"tbsp"}], preparation_steps:["Cook and cool vermicelli.","Pan-fry tofu until golden. Cool and slice.","Shred lettuce. Julienne cucumber and carrot.","Make dressing: lime juice, soy sauce and sugar.","Combine noodles, lettuce, cucumber, carrot and sprouts.","Add tofu and fresh herbs.","Dress and toss well.","Top with peanuts."], chef_notes:"This is a vegan-friendly Vietnamese salad with all the flavours of fresh spring rolls. The herbs are the key — use generous amounts.", serving_suggestions:"Serve as a light vegetarian lunch or starter.", nutrition_estimate:{calories:"225",protein_g:"10",carbohydrates_g:"32",fat_g:"7"}, tags:["Vegetarian","Fresh","Spring Roll","Vietnamese"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Nham (Vietnamese Fermented Pork Roll Salad)", state:"Vietnam", cuisine:"Vietnamese", category:"Salads", difficulty_level:"Medium", prep_time_minutes:30, cook_time_minutes:0, total_time_minutes:30, servings:4, short_description:"A southern Vietnamese fresh salad with nem chua fermented pork, crispy vegetables and roasted peanuts — tangy, complex and utterly unique.", ingredients:[{name:"Nem chua (fermented pork)",quantity:"200",unit:"g"},{name:"Cabbage",quantity:"200",unit:"g"},{name:"Carrot",quantity:"1",unit:"medium"},{name:"Bean sprouts",quantity:"100",unit:"g"},{name:"Fresh herbs",quantity:"1",unit:"bunch"},{name:"Roasted peanuts",quantity:"4",unit:"tbsp"},{name:"Lime juice",quantity:"3",unit:"tbsp"},{name:"Fish sauce",quantity:"2",unit:"tbsp"},{name:"Chilli",quantity:"2",unit:"pieces"},{name:"Garlic",quantity:"2",unit:"cloves"}], preparation_steps:["Slice nem chua into thin rounds.","Shred cabbage finely. Julienne carrot.","Make dressing: lime, fish sauce, garlic and chilli.","Combine nem chua with vegetables and sprouts.","Toss with dressing.","Add fresh herbs.","Top with peanuts.","Serve immediately."], chef_notes:"Nem chua brings a unique sour-savoury flavour from fermentation. If unavailable, substitute with prawn crackers or roasted pork. The fermented flavour is what makes this salad distinctive.", serving_suggestions:"Serve as an appetiser or alongside rice.", nutrition_estimate:{calories:"205",protein_g:"14",carbohydrates_g:"16",fat_g:"10"}, tags:["Fermented Pork","Southern Vietnam","Unique","Sour"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Rau Muong Xao Toi (Water Spinach with Garlic)", state:"Vietnam", cuisine:"Vietnamese", category:"Salads", difficulty_level:"Easy", prep_time_minutes:5, cook_time_minutes:5, total_time_minutes:10, servings:4, short_description:"Vietnam's most beloved green vegetable dish — morning glory stir-fried with loads of garlic and fish sauce until wilted and fragrant. A staple at every Vietnamese table.", ingredients:[{name:"Water spinach (rau muong)",quantity:"500",unit:"g"},{name:"Garlic",quantity:"6",unit:"cloves"},{name:"Fish sauce",quantity:"2",unit:"tbsp"},{name:"Oyster sauce",quantity:"1",unit:"tbsp"},{name:"Oil",quantity:"3",unit:"tbsp"},{name:"Chilli",quantity:"2",unit:"pieces"}], preparation_steps:["Trim water spinach into 10cm pieces.","Smash garlic roughly — do not mince.","Heat wok until smoking hot.","Add oil and garlic. Fry 30 seconds.","Add water spinach all at once.","Stir-fry rapidly over highest heat 2 minutes.","Season with fish sauce and oyster sauce.","Serve immediately — it wilts quickly."], chef_notes:"Maximum heat is essential — water spinach must be cooked fast. It turns slimy if cooked too slowly. The garlic should be golden and fragrant.", serving_suggestions:"Serve immediately as a side dish with rice and other Vietnamese dishes.", nutrition_estimate:{calories:"85",protein_g:"3",carbohydrates_g:"6",fat_g:"6"}, tags:["Water Spinach","Garlic","Quick","Vietnamese Staple"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Goi Xoai (Green Mango Salad)", state:"Vietnam", cuisine:"Vietnamese", category:"Salads", difficulty_level:"Easy", prep_time_minutes:20, cook_time_minutes:5, total_time_minutes:25, servings:4, short_description:"A vibrant Vietnamese green mango salad with dried beef, fresh herbs and roasted peanuts — tangy, sweet, salty and crunchy all at once.", ingredients:[{name:"Green mango",quantity:"3",unit:"medium"},{name:"Dried beef (bo kho)",quantity:"100",unit:"g"},{name:"Shallots",quantity:"3",unit:"pieces"},{name:"Roasted peanuts",quantity:"4",unit:"tbsp"},{name:"Fresh mint",quantity:"1",unit:"bunch"},{name:"Coriander",quantity:"1",unit:"bunch"},{name:"Lime juice",quantity:"3",unit:"tbsp"},{name:"Fish sauce",quantity:"2",unit:"tbsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Chilli",quantity:"2",unit:"pieces"}], preparation_steps:["Peel and shred green mango into thin strips.","Shred dried beef.","Slice shallots thinly.","Make dressing: lime juice, fish sauce, sugar and chilli.","Toss mango, beef and shallots with dressing.","Add fresh herbs and toss.","Top with peanuts.","Serve immediately."], chef_notes:"The mango must be unripe and firm — ripe mango is too soft and sweet. Dried beef adds a chewy, deeply flavoured contrast to the fresh mango.", serving_suggestions:"Serve as a starter or snack with prawn crackers.", nutrition_estimate:{calories:"165",protein_g:"8",carbohydrates_g:"22",fat_g:"6"}, tags:["Green Mango","Dried Beef","Tangy","Vietnamese"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Goi Bap Cai (Cabbage Prawn Salad)", state:"Vietnam", cuisine:"Vietnamese", category:"Salads", difficulty_level:"Easy", prep_time_minutes:20, cook_time_minutes:5, total_time_minutes:25, servings:4, short_description:"A crunchy Vietnamese cabbage salad with prawns and crispy shallots — simple, refreshing and the perfect accompaniment to any Vietnamese meal.", ingredients:[{name:"Cabbage",quantity:"400",unit:"g"},{name:"Cooked prawns",quantity:"200",unit:"g"},{name:"Carrot",quantity:"1",unit:"medium"},{name:"Fresh mint",quantity:"1",unit:"bunch"},{name:"Fried shallots",quantity:"4",unit:"tbsp"},{name:"Roasted peanuts",quantity:"3",unit:"tbsp"},{name:"Lime juice",quantity:"4",unit:"tbsp"},{name:"Fish sauce",quantity:"3",unit:"tbsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Chilli",quantity:"2",unit:"pieces"}], preparation_steps:["Shred cabbage very finely.","Julienne carrot.","Make dressing: lime, fish sauce, sugar and chilli.","Toss cabbage and carrot with dressing.","Add prawns and mint.","Top with fried shallots and peanuts.","Serve immediately."], chef_notes:"Finely shredded cabbage is key — thick pieces make the salad heavy. The fried shallots add essential crunch and aroma.", serving_suggestions:"Serve as a side salad or starter at any Vietnamese meal.", nutrition_estimate:{calories:"165",protein_g:"14",carbohydrates_g:"16",fat_g:"5"}, tags:["Cabbage","Prawn","Crunchy","Vietnamese"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },
  { dish_name:"Goi Ngo Sen (Lotus Stem Salad)", state:"Vietnam", cuisine:"Vietnamese", category:"Salads", difficulty_level:"Medium", prep_time_minutes:25, cook_time_minutes:5, total_time_minutes:30, servings:4, short_description:"An elegant Vietnamese salad of crunchy lotus stems with prawns and pork, dressed in a fragrant lime sauce — one of Vietnam's most beautiful and unique salads.", ingredients:[{name:"Lotus stems",quantity:"300",unit:"g"},{name:"Cooked prawns",quantity:"150",unit:"g"},{name:"Cooked pork belly",quantity:"150",unit:"g"},{name:"Roasted peanuts",quantity:"4",unit:"tbsp"},{name:"Vietnamese coriander",quantity:"1",unit:"bunch"},{name:"Fried shallots",quantity:"3",unit:"tbsp"},{name:"Lime juice",quantity:"4",unit:"tbsp"},{name:"Fish sauce",quantity:"3",unit:"tbsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Chilli",quantity:"2",unit:"pieces"}], preparation_steps:["Peel lotus stems and cut into 5cm pieces.","Soak in acidulated water to prevent browning.","Blanch briefly — 1 minute. Keep crunchy.","Drain and cool.","Slice pork belly thinly.","Make dressing: lime juice, fish sauce, sugar and chilli.","Combine lotus stems, prawns and pork.","Dress and toss. Add Vietnamese coriander.","Top with fried shallots and peanuts."], chef_notes:"Lotus stems have a unique hollow, crunchy texture and mild flavour. They must be soaked in acidulated water immediately after cutting to prevent browning.", serving_suggestions:"Serve as an elegant starter showing off Vietnamese culinary diversity.", nutrition_estimate:{calories:"205",protein_g:"16",carbohydrates_g:"16",fat_g:"8"}, tags:["Lotus Stem","Elegant","Unique","Vietnamese"], img:"https://images.unsplash.com/photo-1540420773420-3366772f4999?w=400&q=80" },

  // ── MAIN COURSES ────────────────────────────────────────────────────────────
  { dish_name:"Banh Mi Sandwich", state:"Vietnam", cuisine:"Vietnamese", category:"Main Courses", difficulty_level:"Easy", prep_time_minutes:20, cook_time_minutes:10, total_time_minutes:30, servings:4, short_description:"The world's greatest sandwich — crispy baguette with pate, cold cuts, pickled vegetables and fresh herbs. Vietnam's most internationally famous street food.", ingredients:[{name:"Vietnamese baguette",quantity:"4",unit:"pieces"},{name:"Pork pate",quantity:"100",unit:"g"},{name:"Cha lua pork sausage",quantity:"200",unit:"g"},{name:"Pickled daikon and carrot",quantity:"200",unit:"g"},{name:"Cucumber",quantity:"1",unit:"medium"},{name:"Coriander",quantity:"1",unit:"bunch"},{name:"Chilli",quantity:"4",unit:"pieces"},{name:"Mayonnaise",quantity:"4",unit:"tbsp"},{name:"Soy sauce",quantity:"1",unit:"tbsp"},{name:"Black pepper",quantity:"0.5",unit:"tsp"}], preparation_steps:["Quick-pickle daikon and carrot if not ready.","Warm baguette until exterior is crispy.","Spread pate on bottom half, mayo on top.","Layer with cha lua slices.","Add pickled vegetables and cucumber.","Add coriander sprigs and chilli slices.","Season with black pepper.","Press together and wrap in paper."], chef_notes:"The Vietnamese baguette is uniquely light and airy inside with a thin crispy shell. Use within minutes of baking for authentic banh mi experience.", serving_suggestions:"Wrap in paper and eat immediately on the go, street food style.", nutrition_estimate:{calories:"385",protein_g:"18",carbohydrates_g:"48",fat_g:"14"}, tags:["Sandwich","Street Food","Fusion","Iconic"], img:"https://images.unsplash.com/photo-1582878826629-33b7f57b2a3c?w=400&q=80" },
  { dish_name:"Bo Luc Lac (Shaking Beef)", state:"Vietnam", cuisine:"Vietnamese", category:"Main Courses", difficulty_level:"Easy", prep_time_minutes:20, cook_time_minutes:10, total_time_minutes:30, servings:4, short_description:"Vietnam's most celebrated beef dish — tender cubes of beef shaken in a screaming hot wok with garlic and butter, served on watercress with lime-pepper dipping sauce.", ingredients:[{name:"Beef sirloin or tenderloin",quantity:"500",unit:"g"},{name:"Garlic",quantity:"6",unit:"cloves"},{name:"Butter",quantity:"2",unit:"tbsp"},{name:"Soy sauce",quantity:"3",unit:"tbsp"},{name:"Oyster sauce",quantity:"2",unit:"tbsp"},{name:"Sugar",quantity:"1",unit:"tbsp"},{name:"Watercress or lettuce",quantity:"200",unit:"g"},{name:"Tomatoes",quantity:"2",unit:"medium"},{name:"Lime juice",quantity:"3",unit:"tbsp"},{name:"Black pepper",quantity:"2",unit:"tsp"},{name:"Red onion",quantity:"1",unit:"medium"}], preparation_steps:["Cut beef into 2cm cubes. Marinate with soy sauce, oyster sauce and sugar.","Heat wok until smoking hot.","Add butter and beef. Shake the wok vigorously — this is the 'luc lac' technique.","Cook 2 minutes only for medium-rare.","Add garlic in last 30 seconds.","Make dipping sauce: lime juice and black pepper.","Arrange watercress on plate with tomatoes.","Pile beef on top. Serve with lime-pepper sauce."], chef_notes:"The 'shaking' technique keeps the beef moving constantly in the hot wok — this creates even caramelisation without overcooking. Beef should be medium-rare inside.", serving_suggestions:"Serve on watercress with rice. Dip each piece in lime-pepper sauce.", nutrition_estimate:{calories:"345",protein_g:"32",carbohydrates_g:"10",fat_g:"18"}, tags:["Beef","Shaking Wok","French-Vietnamese","Butter"], img:"https://images.unsplash.com/photo-1580822184713-fc5400e7fe10?w=400&q=80" },
  { dish_name:"Ca Kho To (Caramelised Fish in Claypot)", state:"Vietnam", cuisine:"Vietnamese", category:"Main Courses", difficulty_level:"Medium", prep_time_minutes:15, cook_time_minutes:45, total_time_minutes:60, servings:4, short_description:"Vietnam's iconic claypot fish — catfish caramelised in coconut water with fish sauce, ginger and chilli until the sauce is dark, thick and sticky-sweet.", ingredients:[{name:"Catfish or salmon",quantity:"600",unit:"g"},{name:"Coconut water",quantity:"300",unit:"ml"},{name:"Fish sauce",quantity:"4",unit:"tbsp"},{name:"Sugar",quantity:"3",unit:"tbsp"},{name:"Ginger",quantity:"30",unit:"g"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Shallots",quantity:"3",unit:"pieces"},{name:"Bird's eye chilli",quantity:"3",unit:"pieces"},{name:"Black pepper",quantity:"1",unit:"tsp"},{name:"Spring onion",quantity:"3",unit:"stalks"}], preparation_steps:["Cut fish into thick pieces.","Caramelise sugar in claypot or heavy pan until amber.","Add fish sauce carefully — it will spit.","Add coconut water, ginger, garlic, shallots and chilli.","Add fish pieces.","Simmer on very low heat 40 minutes.","Sauce should reduce to thick, dark glaze.","Garnish with spring onion and pepper.","Serve with plain white rice."], chef_notes:"The caramelisation is what gives ca kho to its signature dark colour and complex flavour. Low and slow is essential — rushing creates a burnt, bitter sauce.", serving_suggestions:"Serve with lots of plain white rice — the sauce is intensely flavoured.", nutrition_estimate:{calories:"285",protein_g:"28",carbohydrates_g:"20",fat_g:"10"}, tags:["Claypot","Caramelised Fish","Slow Cook","Vietnamese"], img:"https://images.unsplash.com/photo-1580822184713-fc5400e7fe10?w=400&q=80" },
  { dish_name:"Com Tam (Broken Rice with Pork)", state:"Vietnam", cuisine:"Vietnamese", category:"Main Courses", difficulty_level:"Medium", prep_time_minutes:30, cook_time_minutes:30, total_time_minutes:60, servings:4, short_description:"Saigon's most beloved street food dish — broken rice with grilled pork chop, shredded pork skin, steamed egg cake and all the essential accompaniments.", ingredients:[{name:"Broken jasmine rice",quantity:"400",unit:"g"},{name:"Pork chops",quantity:"4",unit:"pieces"},{name:"Lemongrass",quantity:"2",unit:"stalks"},{name:"Fish sauce",quantity:"4",unit:"tbsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Eggs",quantity:"3",unit:"large"},{name:"Cucumber",quantity:"1",unit:"medium"},{name:"Spring onion",quantity:"4",unit:"stalks"},{name:"Nuoc cham sauce",quantity:"6",unit:"tbsp"}], preparation_steps:["Marinate pork chops with fish sauce, sugar, lemongrass and garlic overnight.","Grill pork chops on hot grill until charred.","Make bi: steam egg mixture in mould until set.","Cook broken rice — it has softer, stickier texture than regular rice.","Make nuoc cham dipping sauce.","Assemble plate: rice, pork chop, sliced egg cake, cucumber.","Top with fried shallots and spring onion oil.","Serve with nuoc cham."], chef_notes:"Broken rice (com tam) has a distinctly softer, stickier texture than whole grain rice — it absorbs nuoc cham beautifully. It was historically cheaper rice used by the poor.", serving_suggestions:"Serve on a plate with all components arranged separately. Drizzle nuoc cham.", nutrition_estimate:{calories:"525",protein_g:"34",carbohydrates_g:"62",fat_g:"16"}, tags:["Broken Rice","Saigon","Street Food","Iconic"], img:"https://images.unsplash.com/photo-1574484284002-952d92456975?w=400&q=80" },
  { dish_name:"Thit Kho Trung (Braised Pork and Eggs)", state:"Vietnam", cuisine:"Vietnamese", category:"Main Courses", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:60, total_time_minutes:75, servings:6, short_description:"Vietnam's ultimate Tet dish — pork belly and boiled eggs slowly braised in coconut water and fish sauce until the pork is fall-apart tender and the eggs are golden brown.", ingredients:[{name:"Pork belly",quantity:"800",unit:"g"},{name:"Hard boiled eggs",quantity:"6",unit:"pieces"},{name:"Coconut water",quantity:"400",unit:"ml"},{name:"Fish sauce",quantity:"4",unit:"tbsp"},{name:"Sugar",quantity:"3",unit:"tbsp"},{name:"Shallots",quantity:"4",unit:"pieces"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Black pepper",quantity:"1",unit:"tsp"},{name:"Spring onion",quantity:"3",unit:"stalks"}], preparation_steps:["Cut pork belly into large chunks.","Caramelise sugar until amber. Add fish sauce.","Add pork and coat in caramel.","Add coconut water, shallots and garlic.","Simmer 30 minutes.","Add peeled hard boiled eggs.","Continue simmering 30 more minutes.","Eggs should turn golden brown, pork should be tender.","Season and serve with rice."], chef_notes:"Thit kho trung is the defining dish of Tet (Vietnamese New Year) — cooked in advance and eaten over the holiday. The coconut water adds natural sweetness. Never use regular water.", serving_suggestions:"Serve with plain rice and pickled mustard greens (dua chua).", nutrition_estimate:{calories:"485",protein_g:"28",carbohydrates_g:"14",fat_g:"36"}, tags:["Tet","Braised Pork","New Year","Vietnamese"], img:"https://images.unsplash.com/photo-1574484284002-952d92456975?w=400&q=80" },
  { dish_name:"Ca Chien (Vietnamese Fried Fish)", state:"Vietnam", cuisine:"Vietnamese", category:"Main Courses", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:15, total_time_minutes:30, servings:4, short_description:"A whole fish fried until golden and crispy, served with ginger-fish sauce dipping sauce and fresh herbs — simple Vietnamese home cooking at its finest.", ingredients:[{name:"Whole fish",quantity:"800",unit:"g"},{name:"Ginger",quantity:"30",unit:"g"},{name:"Garlic",quantity:"4",unit:"cloves"},{name:"Fish sauce",quantity:"3",unit:"tbsp"},{name:"Lime juice",quantity:"2",unit:"tbsp"},{name:"Chilli",quantity:"2",unit:"pieces"},{name:"Turmeric",quantity:"0.5",unit:"tsp"},{name:"Oil for frying",quantity:"2",unit:"cups"},{name:"Fresh herbs",quantity:"1",unit:"bunch"},{name:"Cucumber",quantity:"1",unit:"medium"}], preparation_steps:["Score fish with deep diagonal cuts on both sides.","Rub inside and out with turmeric, salt and garlic.","Deep fry whole fish at 180°C until golden — 5-7 minutes per side.","Make dipping sauce: fish sauce, lime juice, ginger, chilli and garlic.","Arrange on platter with fresh herbs.","Serve dipping sauce alongside."], chef_notes:"Scoring the fish deeply allows the turmeric marinade to penetrate and ensures even cooking. The fish should be completely crispy all over.", serving_suggestions:"Serve with dipping sauce, fresh herbs, rice and canh soup.", nutrition_estimate:{calories:"265",protein_g:"32",carbohydrates_g:"4",fat_g:"14"}, tags:["Fried Fish","Simple","Home Cooking","Vietnamese"], img:"https://images.unsplash.com/photo-1580822184713-fc5400e7fe10?w=400&q=80" },
  { dish_name:"Bun Thit Nuong (BBQ Pork Noodle Bowl)", state:"Vietnam", cuisine:"Vietnamese", category:"Main Courses", difficulty_level:"Medium", prep_time_minutes:30, cook_time_minutes:20, total_time_minutes:50, servings:4, short_description:"A Southern Vietnamese noodle bowl with grilled lemongrass pork over cold rice vermicelli, fresh herbs, pickled vegetables and nuoc cham — the perfect meal in a bowl.", ingredients:[{name:"Pork shoulder",quantity:"500",unit:"g"},{name:"Lemongrass",quantity:"3",unit:"stalks"},{name:"Garlic",quantity:"5",unit:"cloves"},{name:"Fish sauce",quantity:"4",unit:"tbsp"},{name:"Sugar",quantity:"2",unit:"tbsp"},{name:"Rice vermicelli",quantity:"300",unit:"g"},{name:"Lettuce",quantity:"200",unit:"g"},{name:"Bean sprouts",quantity:"150",unit:"g"},{name:"Fresh herbs assorted",quantity:"1",unit:"bunch"},{name:"Pickled carrot and daikon",quantity:"150",unit:"g"},{name:"Roasted peanuts",quantity:"4",unit:"tbsp"}], preparation_steps:["Thinly slice pork. Marinate with lemongrass, garlic, fish sauce and sugar.","Grill pork over high heat until charred and fragrant.","Cook vermicelli, rinse under cold water.","Assemble bowls: vermicelli on bottom, then lettuce and herbs.","Top with grilled pork, pickled vegetables and peanuts.","Pour nuoc cham dressing generously over everything.","Toss before eating."], chef_notes:"The contrast of cold noodles, warm grilled pork and room temperature herbs with the tangy nuoc cham dressing is what makes this dish spectacular. Do not substitute cold noodles with hot.", serving_suggestions:"Serve with extra nuoc cham on the side. Toss everything together before eating.", nutrition_estimate:{calories:"445",protein_g:"30",carbohydrates_g:"52",fat_g:"14"}, tags:["BBQ Pork","Noodle Bowl","Southern Vietnam","Fresh"], img:"https://images.unsplash.com/photo-1582878826629-33b7f57b2a3c?w=400&q=80" },
  { dish_name:"Cha Ca La Vong (Turmeric Fish with Dill)", state:"Vietnam", cuisine:"Vietnamese", category:"Main Courses", difficulty_level:"Medium", prep_time_minutes:30, cook_time_minutes:15, total_time_minutes:45, servings:4, short_description:"Hanoi's most legendary restaurant dish — turmeric-marinated catfish sizzled in butter with dill and spring onion at the table, eaten with vermicelli and peanuts.", ingredients:[{name:"Catfish or firm white fish",quantity:"600",unit:"g"},{name:"Turmeric",quantity:"2",unit:"tsp"},{name:"Galangal",quantity:"20",unit:"g"},{name:"Fish sauce",quantity:"3",unit:"tbsp"},{name:"Shrimp paste",quantity:"1",unit:"tsp"},{name:"Fresh dill",quantity:"2",unit:"bunches"},{name:"Spring onion",quantity:"6",unit:"stalks"},{name:"Butter",quantity:"3",unit:"tbsp"},{name:"Vermicelli",quantity:"200",unit:"g"},{name:"Roasted peanuts",quantity:"4",unit:"tbsp"}], preparation_steps:["Marinate fish with turmeric, galangal, fish sauce and shrimp paste 1 hour.","Grill or pan-fry fish until golden.","Bring to table on a sizzling pan.","Add butter at the table.","Add huge handfuls of dill and spring onion — they cook briefly in the hot pan.","Serve with cold vermicelli, peanuts and nuoc cham.","Wrap fish and herbs in lettuce to eat."], chef_notes:"Cha ca La Vong is so beloved in Hanoi that the restaurant that created it has its own street named after it. The dill must be fresh and abundant — it is not a garnish but a main component.", serving_suggestions:"Serve sizzling at the table. Wrap in lettuce with noodles and peanuts.", nutrition_estimate:{calories:"345",protein_g:"32",carbohydrates_g:"22",fat_g:"14"}, tags:["Hanoi","Turmeric Fish","Dill","Legendary"], img:"https://images.unsplash.com/photo-1580822184713-fc5400e7fe10?w=400&q=80" },
  { dish_name:"Hu Tieu Nam Vang (Phnom Penh Noodle Soup)", state:"Vietnam", cuisine:"Vietnamese", category:"Main Courses", difficulty_level:"Medium", prep_time_minutes:20, cook_time_minutes:60, total_time_minutes:80, servings:4, short_description:"A clear, sweet pork broth with chewy tapioca noodles, pork, prawns and quail eggs — Southern Vietnam's beloved Cambodian-influenced noodle dish.", ingredients:[{name:"Pork bones",quantity:"500",unit:"g"},{name:"Dried squid",quantity:"30",unit:"g"},{name:"Daikon radish",quantity:"200",unit:"g"},{name:"Hu tieu noodles",quantity:"400",unit:"g"},{name:"Prawns",quantity:"200",unit:"g"},{name:"Sliced pork",quantity:"200",unit:"g"},{name:"Quail eggs",quantity:"8",unit:"pieces"},{name:"Fish sauce",quantity:"3",unit:"tbsp"},{name:"Sugar",quantity:"1",unit:"tbsp"},{name:"Fried garlic",quantity:"3",unit:"tbsp"}], preparation_steps:["Simmer pork bones with dried squid and daikon 1 hour.","Season with fish sauce and sugar.","Cook noodles separately.","Poach prawns and pork slices in broth briefly.","Boil quail eggs and peel.","Place noodles in bowls with toppings.","Ladle clear broth over.","Top with fried garlic, spring onion and white pepper."], chef_notes:"Dried squid in the broth adds a unique sweetness that defines hu tieu. The broth should be very clear and naturally sweet without being cloying.", serving_suggestions:"Serve with bean sprouts, lime, chilli and extra fish sauce.", nutrition_estimate:{calories:"365",protein_g:"26",carbohydrates_g:"48",fat_g:"8"}, tags:["Noodle Soup","Southern Vietnam","Clear Broth","Cambodian Influence"], img:"https://images.unsplash.com/photo-1582878826629-33b7f57b2a3c?w=400&q=80" },

  // ── DESSERTS ────────────────────────────────────────────────────────────────
  { dish_name:"Che Ba Mau (Three Colour Dessert)", state:"Vietnam", cuisine:"Vietnamese", category:"Desserts", difficulty_level:"Easy", prep_time_minutes:20, cook_time_minutes:10, total_time_minutes:30, servings:4, short_description:"Vietnam's most colourful dessert — layers of green pandan jelly, yellow mung bean, red beans and coconut milk over shaved ice. Beautiful, refreshing and beloved.", ingredients:[{name:"Mung beans",quantity:"150",unit:"g"},{name:"Red beans",quantity:"100",unit:"g"},{name:"Green pandan jelly",quantity:"150",unit:"g"},{name:"Coconut milk",quantity:"400",unit:"ml"},{name:"Sugar",quantity:"80",unit:"g"},{name:"Salt",quantity:"0.5",unit:"tsp"},{name:"Shaved ice",quantity:"4",unit:"cups"},{name:"Pandan extract",quantity:"1",unit:"tsp"}], preparation_steps:["Cook mung beans with sugar until soft. Cool.","Cook red beans with sugar until tender. Cool.","Make pandan jelly and cut into cubes.","Warm coconut milk with salt and sugar.","Fill tall glasses with shaved ice.","Layer red beans, mung beans and pandan jelly over ice.","Pour warm coconut milk over.","Serve immediately."], chef_notes:"The three colours — red, yellow and green — are as important as the flavour. Layer them separately for visual impact. The contrast of cold ice and warm coconut milk is the magic.", serving_suggestions:"Serve in tall glasses over shaved ice. A Vietnamese street dessert staple.", nutrition_estimate:{calories:"285",protein_g:"6",carbohydrates_g:"52",fat_g:"8"}, tags:["Three Colour","Street Dessert","Coconut Milk","Vietnamese"], img:"https://images.unsplash.com/photo-1558024920-b41e1887dc32?w=400&q=80" },
  { dish_name:"Banh Flan (Vietnamese Crème Caramel)", state:"Vietnam", cuisine:"Vietnamese", category:"Desserts", difficulty_level:"Medium", prep_time_minutes:20, cook_time_minutes:40, total_time_minutes:240, servings:6, short_description:"Vietnam's beloved French-influenced crème caramel — richer and more eggy than the French version, often served over ice with black coffee poured over. A perfect fusion dessert.", ingredients:[{name:"Eggs",quantity:"4",unit:"large"},{name:"Egg yolks",quantity:"2",unit:"large"},{name:"Sweetened condensed milk",quantity:"200",unit:"ml"},{name:"Whole milk",quantity:"300",unit:"ml"},{name:"Sugar",quantity:"100",unit:"g"},{name:"Water",quantity:"2",unit:"tbsp"},{name:"Vanilla",quantity:"1",unit:"tsp"},{name:"Strong black coffee",quantity:"4",unit:"tbsp"}], preparation_steps:["Make caramel: cook sugar until amber. Add water carefully.","Pour into ramekins. Let set.","Beat eggs with condensed milk, regular milk and vanilla.","Strain mixture through fine sieve.","Pour over caramel in ramekins.","Steam or bake in water bath at 160°C for 40 minutes.","Cool and refrigerate 3 hours minimum.","Unmould and serve with black coffee poured over."], chef_notes:"Vietnamese banh flan uses condensed milk for extra richness. The black coffee poured over at serving is uniquely Vietnamese — it adds a bittersweet contrast.", serving_suggestions:"Unmould onto plates. Pour a shot of Vietnamese black coffee over each.", nutrition_estimate:{calories:"265",protein_g:"8",carbohydrates_g:"38",fat_g:"10"}, tags:["French Influence","Crème Caramel","Coffee","Vietnamese Dessert"], img:"https://images.unsplash.com/photo-1563805042-7684c019e1cb?w=400&q=80" },
  { dish_name:"Che Dau Xanh (Mung Bean Pudding)", state:"Vietnam", cuisine:"Vietnamese", category:"Desserts", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:40, total_time_minutes:50, servings:6, short_description:"Vietnam's most comforting dessert soup — soft mung beans in sweetened coconut milk with pandan fragrance. Simple, nourishing and deeply Vietnamese.", ingredients:[{name:"Split mung beans",quantity:"250",unit:"g"},{name:"Coconut milk",quantity:"300",unit:"ml"},{name:"Sugar",quantity:"80",unit:"g"},{name:"Pandan leaves",quantity:"3",unit:"pieces"},{name:"Salt",quantity:"0.5",unit:"tsp"},{name:"Tapioca pearls",quantity:"50",unit:"g"}], preparation_steps:["Soak mung beans 2 hours. Drain.","Cook mung beans with pandan leaves until very soft.","Remove pandan. Add sugar and salt.","Cook tapioca pearls separately until transparent.","Add tapioca to mung bean mixture.","Heat coconut milk gently. Pour over beans when serving.","Serve warm or chilled."], chef_notes:"Mung beans should be very soft and starting to break down into a creamy texture. The pandan leaves are essential for the fragrant character.", serving_suggestions:"Serve warm or cold depending on season.", nutrition_estimate:{calories:"245",protein_g:"8",carbohydrates_g:"44",fat_g:"6"}, tags:["Mung Bean","Coconut Milk","Comforting","Vietnamese"], img:"https://images.unsplash.com/photo-1558024920-b41e1887dc32?w=400&q=80" },
  { dish_name:"Banh Chuoi Nuong (Baked Banana Cake)", state:"Vietnam", cuisine:"Vietnamese", category:"Desserts", difficulty_level:"Easy", prep_time_minutes:15, cook_time_minutes:40, total_time_minutes:55, servings:8, short_description:"A fragrant Vietnamese banana cake baked with coconut milk and pandan — dense, moist and fragrant. A simple but completely addictive dessert.", ingredients:[{name:"Ripe bananas",quantity:"8",unit:"medium"},{name:"Coconut milk",quantity:"300",unit:"ml"},{name:"Sugar",quantity:"80",unit:"g"},{name:"Glutinous rice flour",quantity:"100",unit:"g"},{name:"Tapioca flour",quantity:"50",unit:"g"},{name:"Salt",quantity:"0.5",unit:"tsp"},{name:"Pandan extract",quantity:"1",unit:"tsp"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"}], preparation_steps:["Mash bananas roughly — keep some texture.","Mix coconut milk, sugar, flours, salt and pandan extract.","Fold in mashed bananas.","Pour into greased baking dish.","Sprinkle sesame seeds on top.","Bake at 180°C for 35-40 minutes.","Cool before cutting — it firms as it cools.","Cut into squares."], chef_notes:"Use very ripe bananas — the sweeter and more spotted the better. The cake should be dense and slightly sticky, not fluffy like Western banana bread.", serving_suggestions:"Serve at room temperature cut into squares.", nutrition_estimate:{calories:"225",protein_g:"3",carbohydrates_g:"42",fat_g:"7"}, tags:["Banana","Baked","Coconut","Vietnamese Dessert"], img:"https://images.unsplash.com/photo-1563805042-7684c019e1cb?w=400&q=80" },
  { dish_name:"Sinh To Bo (Vietnamese Avocado Shake)", state:"Vietnam", cuisine:"Vietnamese", category:"Desserts", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:0, total_time_minutes:10, servings:2, short_description:"Vietnam's beloved avocado shake — blended with condensed milk and ice into a thick, creamy, sweet dessert drink. Vietnamese treat avocado as a dessert, not a savoury ingredient.", ingredients:[{name:"Ripe avocados",quantity:"2",unit:"large"},{name:"Sweetened condensed milk",quantity:"4",unit:"tbsp"},{name:"Whole milk",quantity:"100",unit:"ml"},{name:"Ice",quantity:"2",unit:"cups"},{name:"Sugar",quantity:"1",unit:"tbsp"}], preparation_steps:["Halve and scoop avocado flesh.","Blend avocado with condensed milk, milk and sugar.","Add ice and blend until smooth and thick.","Taste and adjust sweetness.","Pour into tall glasses.","Serve immediately with a thick straw."], chef_notes:"Vietnamese sinh to is much thicker than a Western smoothie — it should be spoonable. Use very ripe, buttery avocados for the richest flavour. Condensed milk is non-negotiable.", serving_suggestions:"Serve immediately in tall glasses. Do not delay — avocado oxidises quickly.", nutrition_estimate:{calories:"345",protein_g:"5",carbohydrates_g:"36",fat_g:"22"}, tags:["Avocado","Shake","Sweet","Vietnamese Dessert"], img:"https://images.unsplash.com/photo-1558024920-b41e1887dc32?w=400&q=80" },
  { dish_name:"Banh Troi (Floating Rice Cakes)", state:"Vietnam", cuisine:"Vietnamese", category:"Desserts", difficulty_level:"Medium", prep_time_minutes:30, cook_time_minutes:15, total_time_minutes:45, servings:6, short_description:"White glutinous rice balls filled with palm sugar floating in ginger syrup — a traditional Vietnamese dessert eaten on Han Thuc (Cold Food Festival).", ingredients:[{name:"Glutinous rice flour",quantity:"300",unit:"g"},{name:"Palm sugar",quantity:"150",unit:"g"},{name:"Ginger",quantity:"50",unit:"g"},{name:"Sugar",quantity:"100",unit:"g"},{name:"Water",quantity:"400",unit:"ml"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"},{name:"Salt",quantity:"0.25",unit:"tsp"}], preparation_steps:["Mix rice flour with warm water to smooth dough.","Break palm sugar into small pieces.","Wrap small portions of dough around palm sugar.","Roll into smooth balls.","Boil in water until they float, then 2 more minutes.","Make ginger syrup: simmer water, sugar and ginger slices.","Serve rice balls in warm ginger syrup.","Top with toasted sesame seeds."], chef_notes:"The balls should be perfectly smooth and round. They float when cooked — leave them for 2 more minutes after floating to ensure the palm sugar inside has melted.", serving_suggestions:"Serve warm in ginger syrup. Traditional on Han Thuc festival.", nutrition_estimate:{calories:"265",protein_g:"3",carbohydrates_g:"56",fat_g:"2"}, tags:["Rice Balls","Palm Sugar","Traditional","Festival"], img:"https://images.unsplash.com/photo-1558024920-b41e1887dc32?w=400&q=80" },
  { dish_name:"Che Thai (Thai-Inspired Vietnamese Dessert)", state:"Vietnam", cuisine:"Vietnamese", category:"Desserts", difficulty_level:"Easy", prep_time_minutes:20, cook_time_minutes:10, total_time_minutes:30, servings:4, short_description:"A colourful Vietnamese dessert soup with mixed jellies, coconut cream, fruits and tapioca — refreshing, sweet and visually beautiful. Popular throughout South-East Asia.", ingredients:[{name:"Grass jelly",quantity:"150",unit:"g"},{name:"Coconut jelly",quantity:"150",unit:"g"},{name:"Jackfruit",quantity:"100",unit:"g"},{name:"Lychee",quantity:"12",unit:"pieces"},{name:"Coconut cream",quantity:"300",unit:"ml"},{name:"Sugar",quantity:"60",unit:"g"},{name:"Tapioca pearls",quantity:"50",unit:"g"},{name:"Crushed ice",quantity:"4",unit:"cups"},{name:"Pandan jelly",quantity:"100",unit:"g"}], preparation_steps:["Cook tapioca pearls until transparent. Cool.","Cut all jellies into cubes.","Prepare coconut cream with sugar and salt.","Fill large bowls with crushed ice.","Arrange jellies, jackfruit and lychee over ice.","Add tapioca pearls.","Pour coconut cream over everything.","Serve immediately."], chef_notes:"The variety of colours and textures is what makes che thai appealing. Use at least 4 different jellies for visual impact. Serve very cold.", serving_suggestions:"Serve in large bowls or glasses over crushed ice.", nutrition_estimate:{calories:"265",protein_g:"2",carbohydrates_g:"52",fat_g:"8"}, tags:["Mixed Dessert","Coconut","Colourful","Vietnamese"], img:"https://images.unsplash.com/photo-1558024920-b41e1887dc32?w=400&q=80" },
  { dish_name:"Nuoc Cot Dua (Coconut Pudding)", state:"Vietnam", cuisine:"Vietnamese", category:"Desserts", difficulty_level:"Easy", prep_time_minutes:10, cook_time_minutes:15, total_time_minutes:25, servings:6, short_description:"A silky Vietnamese coconut pudding set with agar agar — delicate, fragrant and wobbly. Served chilled as a simple, elegant Vietnamese dessert.", ingredients:[{name:"Coconut milk",quantity:"600",unit:"ml"},{name:"Agar agar powder",quantity:"5",unit:"g"},{name:"Sugar",quantity:"80",unit:"g"},{name:"Salt",quantity:"0.25",unit:"tsp"},{name:"Pandan extract",quantity:"1",unit:"tsp"},{name:"Toasted coconut",quantity:"3",unit:"tbsp"}], preparation_steps:["Dissolve agar in 100ml cold coconut milk.","Heat remaining coconut milk with sugar and salt.","Add dissolved agar mixture. Stir well.","Add pandan extract.","Bring to simmer stirring constantly.","Pour into moulds or glasses.","Cool to room temperature then refrigerate 2 hours.","Unmould and top with toasted coconut."], chef_notes:"Agar sets firmer than gelatin and at room temperature — do not refrigerate before it sets naturally. The texture should be silky and wobbly.", serving_suggestions:"Serve chilled, unmoulded onto plates with toasted coconut.", nutrition_estimate:{calories:"185",protein_g:"2",carbohydrates_g:"28",fat_g:"9"}, tags:["Coconut Pudding","Agar","Silky","Vietnamese Dessert"], img:"https://images.unsplash.com/photo-1558024920-b41e1887dc32?w=400&q=80" },
  { dish_name:"Banh Pia (Vietnamese Mooncake)", state:"Vietnam", cuisine:"Vietnamese", category:"Desserts", difficulty_level:"Hard", prep_time_minutes:60, cook_time_minutes:30, total_time_minutes:90, servings:12, short_description:"A flaky, layered Vietnamese pastry from Soc Trang — spiral-layered dough filled with durian, mung bean or taro paste. A beloved Teochew-Vietnamese confection.", ingredients:[{name:"Plain flour",quantity:"300",unit:"g"},{name:"Lard or shortening",quantity:"150",unit:"g"},{name:"Mung bean paste",quantity:"400",unit:"g"},{name:"Salted egg yolks",quantity:"6",unit:"pieces"},{name:"Sugar",quantity:"60",unit:"g"},{name:"Water",quantity:"100",unit:"ml"},{name:"Egg yolk for wash",quantity:"2",unit:"pieces"},{name:"Sesame seeds",quantity:"2",unit:"tbsp"}], preparation_steps:["Make water dough: flour, lard and water.","Make oil dough: flour and lard only.","Wrap oil dough inside water dough. Roll and fold 3 times.","Roll into log and cut into portions.","Flatten each portion and fill with mung bean paste and egg yolk.","Seal and shape into round cakes.","Brush with egg wash. Sprinkle sesame seeds.","Bake at 180°C for 25 minutes until golden."], chef_notes:"The laminating technique (folding oil and water doughs together) creates the spiral, flaky layers. Lard is traditional and gives the most delicate layers — butter is a substitute.", serving_suggestions:"Serve with Chinese tea. Keeps for one week at room temperature.", nutrition_estimate:{calories:"285",protein_g:"6",carbohydrates_g:"36",fat_g:"14"}, tags:["Pastry","Layered","Mooncake","Vietnamese-Chinese"], img:"https://images.unsplash.com/photo-1563805042-7684c019e1cb?w=400&q=80" },
];



